/**
 * CRM Lazy Chunk: egg
 * Role-gated: L1 Super Admin only
 *
 * Self-contained IIFE. Accesses shared state through window.* globals only.
 * Loaded on-demand by navigateTo() role-gated chunk loader in script.js.
 * Attaches all public functions to window.app via Object.assign at the bottom.
 *
 * Generated by _patch_chunks.mjs — do NOT edit the comment block above.
 */
(() => {
    // ── Live bindings to IIFE-private state ──────────────────────────────
    // _state.cu / _state.cv hit live getters/setters on window._appState
    // so reads always see the current value and writes (e.g. _state.cv =
    // 'stock_take') propagate back into the main IIFE's _currentView.
    // Body identifiers _currentUser / _currentView were rewritten to
    // _state.cu / _state.cv by the patch script.
    const _state = window._appState;
    const _utils = window._crmUtils;
    const isSystemAdmin        = (u) => _utils.isSystemAdmin(u || _state.cu);
    const isMarketingManager   = (u) => _utils.isMarketingManager(u || _state.cu);
    const isAgent              = (u) => _utils.isAgent(u || _state.cu);
    const isManagement         = (u) => _utils.isManagement(u || _state.cu);
    const isTeamLeaderOrAbove  = (u) => _utils.isTeamLeaderOrAbove(u || _state.cu);
    const isStockTakeStaff     = (u) => _utils.isStockTakeStaff(u || _state.cu);
    const escapeHtml           = (...a) => _utils.escapeHtml(...a);
    const isMobile             = () => _utils.isMobile();
    const withTimeout          = (...a) => _utils.withTimeout(...a);
    const timeAgo              = (...a) => _utils.timeAgo(...a);
    const generateId           = () => _utils.generateId();
    const debounceCall         = (...a) => window.app.debounceCall(...a);
    const navigateTo           = (v)   => window.app.navigateTo(v);

    // React-island flag (default-on, PROMOTED 2026-06-16 after opt-in verify:
    // useEffect→eggSwitchTab populate confirmed live — 4 tabs, Run wizard content
    // matches legacy, tab-switch works). Kill-switch → legacy: window.__REACT_EGG===false,
    // ?react=0, crm_react_off='1'.
    const _reactEggOn = () => {
        try {
            if (window.__REACT_EGG === false) return false;
            if (/[?&]react=0/.test(location.search)) return false;
            if (localStorage.getItem('crm_react_off') === '1') return false;
            return !!(window.CRMReact && typeof window.CRMReact.mountEggPurchasing === 'function');
        } catch (_) { return false; }
    };

    // NEW full-JSX render path flag — DEFAULT-OFF. Opt-in ONLY via ?react_egg_jsx=1
    // OR localStorage crm_react_egg_jsx='1' (same detection idiom as _reactEggOn,
    // inverted to opt-IN). When ON, showEggPurchasingView hands the island a
    // structured `data` payload so EggPurchasingView renders ALL tabs as REAL JSX
    // (React-state tab switching) and suppresses the by-id #egg-tab-content fill.
    // When OFF (the live default), behavior is byte-for-byte the existing
    // scaffold-shell path (empty #egg-tab-content filled by eggSwitchTab on
    // useEffect onReady). Requires _reactEggOn() to be true as well — this flag
    // only upgrades the EXISTING island block, it never enables the island alone.
    const _reactEggJsxOn = () => {
        // PROMOTED (SW-107): full-JSX render is the DEFAULT.
        // Kill-switch: ?react_egg_jsx=0 or localStorage crm_react_egg_jsx='0'.
        try {
            if (/[?&]react_egg_jsx=0/.test(location.search)) return false;
            if (localStorage.getItem('crm_react_egg_jsx') === '0') return false;
            return true;
        } catch (_) { return true; }
    };
    // AppDataStore, UI, supabase are global — no alias needed.

    // ==================== EGG PURCHASING SYSTEM (Super Admin only) ====================
    // Weekly farm order generation: ingest CSV + XLSX invoices, dedupe against
    // history, reconcile late-arriving "urgent" orders manually, render the
    // Chinese farm order text + KL/PG wholesale/online breakdown, persist to
    // Supabase. Full design captured in conversation at 2026-04-14.
    //
    // Run flow (Tab 1) is a 3-phase wizard where NOTHING hits the database
    // until Commit in Phase 3, so the user can always discard and redo.

    let _eggState = {
        currentTab: 'run',
        currentPhase: 1,
        weekStartDate: null,
        csvFile: null, csvRows: [], csvHeaders: [],
        xlsxFile: null, xlsxRows: [], xlsxHeaders: [],
        normalizedRows: [],     // all rows after filter/map, before dedup
        newRows: [],            // rows not yet in processed_orders history
        urgentOrders: [],       // (legacy, unused in simplified flow — kept for Tab 2)
        matches: [],            // (legacy, unused in simplified flow)
        excludedKeys: new Set(),// unique_keys marked to push up to last week (exclude from current)
        excludedToUrgent: {},   // (legacy, unused in simplified flow)
        lastWeekTopUp: { GOLD: 0, KING: 0 },  // user-entered ad-hoc top-up quantities from last week
        prevRunOrders: [],      // previous committed run's orders — shown as reference in Phase 2
        prevRunMeta: null,      // previous run's egg_run_history record
        config: null,
        farmOrderText: '',
        channelBreakdownText: '',
        channelBreakdownHtml: '',
        stats: {}
    };

    // --- Date helpers ---
    const eggGetCurrentMonday = () => {
        const now = new Date();
        const day = now.getDay();  // 0=Sun, 1=Mon, ... 6=Sat
        const offset = day === 0 ? -6 : 1 - day;
        const mon = new Date(now);
        mon.setDate(now.getDate() + offset);
        mon.setHours(0, 0, 0, 0);
        return mon;
    };

    const eggFormatDateShort = (d) => {
        if (!d) return '';
        const dt = d instanceof Date ? d : new Date(d);
        if (isNaN(dt)) return '';
        return `${String(dt.getDate()).padStart(2,'0')}/${String(dt.getMonth()+1).padStart(2,'0')}/${String(dt.getFullYear()).slice(2)}`;
    };

    const eggFormatDateIso = (d) => {
        if (!d) return '';
        const dt = d instanceof Date ? d : new Date(d);
        if (isNaN(dt)) return '';
        return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,'0')}-${String(dt.getDate()).padStart(2,'0')}`;
    };

    const eggParseFlexibleDate = (val) => {
        if (val == null || val === '') return null;
        if (val instanceof Date) return isNaN(val) ? null : val;
        // Excel serial number (days since 1899-12-30 epoch)
        if (typeof val === 'number') {
            const d = new Date(Math.round((val - 25569) * 86400 * 1000));
            return isNaN(d) ? null : d;
        }
        const s = String(val).trim();
        if (!s) return null;
        // Try dd/mm/yyyy [HH:MM[:SS]]
        let m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})(?:[\s,T]+(\d{1,2}):(\d{2})(?::(\d{2}))?)?/);
        if (m) {
            let [, d, mo, y, hh, mm, ss] = m;
            let year = y.length === 2 ? 2000 + parseInt(y, 10) : parseInt(y, 10);
            return new Date(year, parseInt(mo,10)-1, parseInt(d,10), parseInt(hh||0,10), parseInt(mm||0,10), parseInt(ss||0,10));
        }
        // Try ISO / native parsing
        const iso = new Date(s);
        return isNaN(iso) ? null : iso;
    };

    const eggNormalizeAgentName = (name) => {
        if (!name) return '';
        return String(name).trim().toLowerCase().replace(/\s+/g, ' ');
    };

    // Tolerant numeric parser — CSV/XLSX exports often format quantities with
    // thousands separators (e.g. "1,200") or stray spaces, which Number() turns
    // into NaN → silently dropped as qty<=0. Strip grouping commas/spaces first.
    const eggParseQty = (val) => {
        if (val == null || val === '') return 0;
        if (typeof val === 'number') return isNaN(val) ? 0 : val;
        const n = Number(String(val).replace(/[,\s]/g, ''));
        return isNaN(n) ? 0 : n;
    };

    // --- Config ---
    const eggDefaultConfig = () => ({
        region_mapping: [
            { keyword: 'Bay Avenue, PG', region: 'PG' },
            { keyword: 'Pavillion 2', region: 'KL' },
            { keyword: 'Formula2u, MBB', region: 'IGNORE' },
            { keyword: 'MBB', region: 'IGNORE' }
        ],
        ignore_jb_king: true,
        ignore_jb_gold: true,
        product_mapping: {
            'GOLD FRESH HEALTH PLUS EGG': 'GOLD',
            'KING EGGS': 'KING',
            'KIN EGGS': 'KING'
        },
        wholesale_groups: ['Kim','June','NDV','Liew','Hui Chin','Darren','Sampson'],
        default_region_fallback: 'KL',
        watch_window_weeks: 4,
        // Paste the Apps Script Web App deployment URL here. Leave blank to
        // disable Google Sheets push. See apps_script_egg_sheets.gs in the
        // project root for the script to deploy.
        google_sheets_webhook_url: ''
    });

    const eggLoadConfig = async () => {
        try {
            const rows = await AppDataStore.query('egg_config', { id: 1 });
            if (rows && rows.length > 0 && rows[0].data) {
                _eggState.config = rows[0].data;
                return _eggState.config;
            }
        } catch (err) {
            console.warn('egg: failed to load config, using defaults', err);
        }
        _eggState.config = eggDefaultConfig();
        return _eggState.config;
    };

    const eggSaveConfig = async (newConfig) => {
        try {
            const rows = await AppDataStore.query('egg_config', { id: 1 });
            const payload = {
                data: newConfig,
                updated_at: new Date().toISOString(),
                updated_by: _state.cu?.full_name || _state.cu?.email || 'unknown'
            };
            if (rows && rows.length > 0) {
                await AppDataStore.update('egg_config', rows[0].id, payload);
            } else {
                await AppDataStore.create('egg_config', { id: 1, ...payload });
            }
            _eggState.config = newConfig;
            UI.toast.success('Configuration saved');
        } catch (err) {
            console.error('egg: save config failed', err);
            UI.toast.error('Failed to save config: ' + (err.message || 'unknown'));
        }
    };

    // --- File parsing ---
    const eggReadFile = (file) => new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => resolve(e.target.result);
        reader.onerror = () => reject(new Error('File read failed'));
        if (file.name.toLowerCase().endsWith('.csv')) reader.readAsText(file, 'UTF-8');
        else reader.readAsArrayBuffer(file);
    });

    const eggParseCsv = async (file) => {
        const text = await eggReadFile(file);
        const parsed = Papa.parse(text, { header: true, skipEmptyLines: true });
        return { headers: parsed.meta.fields || [], rows: parsed.data };
    };

    const eggParseXlsx = async (file) => {
        await window._ensureXlsx();
        const buf = await eggReadFile(file);
        const wb = XLSX.read(buf, { type: 'array', cellDates: true });
        const sheet = wb.Sheets[wb.SheetNames[0]];
        const rows = XLSX.utils.sheet_to_json(sheet, { defval: '' });
        const headers = rows.length > 0 ? Object.keys(rows[0]) : [];
        return { headers, rows };
    };

    // --- Row normalization (map CSV + XLSX to a common shape) ---
    // Standard shape: { order_no, product_name, quantity, outlet, order_date, group_name, state, agent_name, source }
    const eggGetField = (row, candidates) => {
        for (const key of candidates) {
            if (row[key] != null && row[key] !== '') return row[key];
            // Case-insensitive fallback
            const found = Object.keys(row).find(k => k.toLowerCase().trim() === key.toLowerCase());
            if (found && row[found] != null && row[found] !== '') return row[found];
        }
        return '';
    };

    const eggNormalizeCsvRow = (row) => ({
        order_no: String(eggGetField(row, ['Order No.', 'Order No', 'OrderNo', 'order_no'])).trim(),
        product_name: String(eggGetField(row, ['Product Name', 'product_name', 'Product'])).trim(),
        product_code: String(eggGetField(row, ['Product Code', 'Item Code', 'SKU', 'Code', 'product_code', 'Item No', 'Item No.'])).trim(),
        quantity: eggParseQty(eggGetField(row, ['Quantity', 'Qty', 'quantity'])),
        outlet: String(eggGetField(row, ['Self Collection', 'Outlet', 'Outlet Name', 'outlet'])).trim(),
        order_date: eggGetField(row, ['Order Date', 'order_date', 'Date']),
        group_name: String(eggGetField(row, ['Group', 'Group Name', 'group_name'])).trim(),
        state: String(eggGetField(row, ['States', 'State', 'state'])).trim(),
        agent_name: String(eggGetField(row, ['Full Name', 'Agent Name', 'Purchase To', 'agent_name'])).trim(),
        source: 'CSV'
    });

    const eggNormalizeXlsxRow = (row) => ({
        order_no: String(eggGetField(row, ['Purchase Number', 'Order No.', 'order_no', 'Purchase No'])).trim(),
        product_name: String(eggGetField(row, ['Product Name', 'product_name'])).trim(),
        product_code: String(eggGetField(row, ['Product Code', 'Item Code', 'SKU', 'Code', 'product_code', 'Item No', 'Item No.'])).trim(),
        quantity: eggParseQty(eggGetField(row, ['Product Quantity', 'Quantity', 'Qty', 'quantity'])),
        outlet: String(eggGetField(row, ['Outlet Name', 'Outlet', 'Self Collection', 'outlet'])).trim(),
        order_date: eggGetField(row, ['Purchase Date Time', 'Order Date', 'Purchase Date', 'order_date']),
        group_name: String(eggGetField(row, ['Group Name', 'Group', 'group_name'])).trim(),
        state: String(eggGetField(row, ['States', 'State', 'state'])).trim(),
        agent_name: String(eggGetField(row, ['Purchase To', 'Full Name', 'Agent Name', 'agent_name'])).trim(),
        source: 'EXCEL'
    });

    // --- Region / product / channel mapping ---
    // All three accept `config` defensively — if called before config is loaded,
    // they fall back to sensible defaults instead of throwing.
    const eggAssignRegion = (outlet, state, config) => {
        const cfg = config || {};
        const outletStr = String(outlet || '').toLowerCase();
        for (const rule of (cfg.region_mapping || [])) {
            if (outletStr.includes(String(rule.keyword).toLowerCase())) {
                return rule.region;
            }
        }
        // Fallback via state
        if (state && /johor/i.test(state)) return 'JB';
        return cfg.default_region_fallback || 'KL';
    };

    const eggMapProduct = (productName, config) => {
        const cfg = config || {};
        const name = String(productName || '').trim();
        const mapping = cfg.product_mapping || {};
        for (const key of Object.keys(mapping)) {
            if (name.toUpperCase().includes(key.toUpperCase())) {
                return mapping[key];
            }
        }
        return 'UNKNOWN';
    };

    const eggClassifyChannel = (groupName, config) => {
        // Rows that match a name in `wholesale_groups` are actually the agent-
        // managed ONLINE orders (the config name is historical — the list holds
        // agent/group identifiers that sell via the online channel). Everything
        // else (no group, or group outside that list) is a Wholesale order.
        if (!groupName) return 'Wholesale';
        const cfg = config || {};
        const g = String(groupName).trim();
        const isInGroupList = (cfg.wholesale_groups || []).some(w => g.toLowerCase().includes(String(w).toLowerCase()));
        return isInGroupList ? 'Online' : 'Wholesale';
    };

    // When order_no is present it uniquely identifies the physical order line.
    // When it is BLANK (older exports, or a renamed order-number column), a bare
    // '-' fallback collapses every distinct blank-order_no line with the same
    // product/qty/region into ONE key — silently dropping real orders in the
    // in-batch dedup and permanently suppressing them in history dedup. Fall back
    // to agent_name + order date so two different agents' (or two dates')
    // blank-order_no lines stay distinct. Rows WITH an order_no keep the exact
    // same key format, so cross-week dedup for the normal case is unchanged; and
    // the history dedup's agent+date+product+qty+region tier still catches a
    // genuine repeat of a blank-order_no line.
    const eggBuildUniqueKey = (r) => {
        if (r.order_no) return `${r.order_no}_${r.product}_${r.quantity}_${r.region}`;
        const agent = String(r.agent_name || '').trim().toUpperCase();
        const dt = String(r.order_date_parsed || r.order_date || '').slice(0, 10);
        return `-|${agent}|${dt}_${r.product}_${r.quantity}_${r.region}`;
    };

    // --- Pipeline step: filter + map all raw rows to the standard shape, apply drop rules ---
    const eggProcessRows = (rawRows, config) => {
        const now = new Date();
        // Future-date cutoff = end of today in local time, so a same-day order
        // with a later clock time (or a timezone-boundary parse) isn't dropped
        // as "future". Anything strictly after today is still excluded.
        const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59, 999);
        const out = [];
        const seenInBatch = new Set();  // in-batch dedup: prevent same row appearing in both CSV + XLSX
        let droppedDupes = 0;
        let droppedFutureDated = 0;
        for (const r of rawRows) {
            // Product mapping first (needed for JB drop rule)
            const product = eggMapProduct(r.product_name, config);
            if (!['GOLD', 'KING'].includes(product)) continue;

            // Region
            const region = eggAssignRegion(r.outlet, r.state, config);
            if (region === 'IGNORE') continue;

            // Drop JB entirely (both GOLD and KING). JB is a MANUAL channel —
            // the farm-order template hardcodes JB to 0 for the super admin to
            // fill in by hand, and NONE of the downstream renderers (eggAggregate,
            // channel breakdown, Google Sheets push) emit a JB section. Letting
            // JB rows survive only persisted them to egg_processed_orders while
            // they vanished from every output, so drop them regardless of the
            // ignore_jb_* flags to keep history consistent with what ships.
            if (region === 'JB') continue;

            // Quantity sanity — tolerant parse so thousands-separated values
            // (e.g. "1,200") aren't NaN→0→silently dropped below.
            const qty = eggParseQty(r.quantity);
            if (qty <= 0) continue;

            // Date filter: only include orders dated on or before end-of-today.
            const od = eggParseFlexibleDate(r.order_date);
            // If date is unparseable, include it (don't drop) — better to show than hide
            if (od && od > todayEnd) { droppedFutureDated++; continue; }

            const channel = eggClassifyChannel(r.group_name, config);
            const normalized = {
                ...r,
                product,
                region,
                quantity: qty,
                channel,
                order_date_parsed: od ? od.toISOString() : null
            };
            normalized.unique_key = eggBuildUniqueKey(normalized);

            // In-batch dedup — CSV + XLSX might both contain the same physical order line
            if (seenInBatch.has(normalized.unique_key)) { droppedDupes++; continue; }
            seenInBatch.add(normalized.unique_key);

            out.push(normalized);
        }
        _eggState.droppedDupes = droppedDupes;
        _eggState.droppedFutureDated = droppedFutureDated;
        return out;
    };

    // --- Dedup against full history ---
    // Three-tier check: unique_key → order_no → agent+date+product+qty+region.
    // The fallback tiers handle cases where region mapping changed or order_no
    // was not stored in older history records. Only SHIPPED rows (no
    // excluded_reason) populate the seen-sets — pushed-up/reconciled rows must
    // not permanently dedup a legitimately-recurring future order line.
    const eggDedupAgainstHistory = async (rows) => {
        try {
            // Full-table read MUST paginate past PostgREST's 1000-row cap.
            // A bare query() returns at most 1000 heap-ordered rows once the
            // table grows, so the most-recent weeks fall outside the window and
            // recently-shipped lines pass dedup as "new" → duplicate farm orders.
            // queryPaged() pages the entire table (ordered by id) so every
            // shipped row populates the seen-sets.
            const history = await AppDataStore.queryPaged('egg_processed_orders', { max: 200000 });
            // Pushed-up / reconciled rows were NOT shipped — they carry an
            // excluded_reason. They must not block a legitimately-recurring
            // identical order line in a later week, so exclude them from every
            // seen-set used for dedup.
            const shipped = (history || []).filter(h => !h.excluded_reason);
            const seenKeys = new Set(shipped.map(h => h.unique_key).filter(Boolean));
            const seenOrderNos = new Set(shipped.map(h => h.order_no).filter(Boolean));
            const seenAgentLines = new Set(
                shipped
                    .filter(h => h.agent_name && h.order_date && h.product && h.quantity != null)
                    // Include region in the fallback key — two orders that differ
                    // only by region (KL vs PG) are NOT duplicates.
                    .map(h => `${String(h.agent_name).trim().toUpperCase()}|${String(h.order_date).slice(0,10)}|${h.product}|${h.quantity}|${h.region || ''}`)
            );
            return rows.filter(r => {
                if (seenKeys.has(r.unique_key)) return false;
                if (r.order_no && seenOrderNos.has(r.order_no)) return false;
                if (r.agent_name && r.order_date_parsed) {
                    const line = `${String(r.agent_name).trim().toUpperCase()}|${String(r.order_date_parsed).slice(0,10)}|${r.product}|${r.quantity}|${r.region || ''}`;
                    if (seenAgentLines.has(line)) return false;
                }
                return true;
            });
        } catch (err) {
            // Fail LOUD, not silent: if the history read fails we cannot verify against
            // past weeks, so every row looks "new" and a blind commit would duplicate
            // farm orders. Warn the user prominently (there is a Phase-2 review before
            // the actual commit) instead of silently passing all rows through.
            console.error('egg: dedup against history FAILED — cannot verify duplicates; returning all rows UNDEDUPED', err);
            try { window.UI?.toast?.error?.('⚠️ Duplicate check failed (order history unavailable). The "new orders" list is NOT verified against past weeks — review carefully before committing to avoid duplicate farm orders.'); } catch (_) { /* toast best-effort */ }
            return rows;
        }
    };

    // --- Aggregate for farm order text ---
    const eggAggregate = (rows) => {
        const sum = { KL: { GOLD: 0, KING: 0 }, PG: { GOLD: 0, KING: 0 } };
        const byGroup = {};
        for (const r of rows) {
            if (!sum[r.region]) continue;
            if (!sum[r.region][r.product]) sum[r.region][r.product] = 0;
            sum[r.region][r.product] += Number(r.quantity) || 0;
            // Only wholesale-channel rows carry geographic group names (KL Cheras, PG Center, etc.)
            if (r.channel === 'Wholesale' && r.group_name) {
                byGroup[r.group_name] = (byGroup[r.group_name] || 0) + (Number(r.quantity) || 0);
            }
        }
        sum.by_group = byGroup;
        return sum;
    };

    const eggAggregateByChannel = (rows) => {
        const sum = {
            KL: { Wholesale: { GOLD:0, KING:0 }, Online: { GOLD:0, KING:0 } },
            PG: { Wholesale: { GOLD:0, KING:0 }, Online: { GOLD:0, KING:0 } }
        };
        for (const r of rows) {
            if (!sum[r.region]) continue;
            if (!sum[r.region][r.channel]) continue;
            sum[r.region][r.channel][r.product] = (sum[r.region][r.channel][r.product]||0) + (Number(r.quantity)||0);
        }
        return sum;
    };

    // --- Farm order text renderers ---
    const eggRenderFarmOrderText = (summary, dateObj) => {
        const d = eggFormatDateShort(dateObj || new Date());
        // NOTE: JB values are MANUAL — the automated pipeline filters JB rows out,
        // but the JB lines stay in the template so the super admin can type the
        // actual JB numbers in the editable Phase 3 preview before sending to the farm.
        return `老师好，這個星期下的单子。
${d}
KL
KINGEGGS 高鮮帝王蛋- ${summary.KL.KING || 0} carton
GOLD FRESH HEALTH PLUS EGG 高鮮蛋 - ${summary.KL.GOLD || 0} cartons

PG
KINGEGGS 高鮮帝王蛋- ${summary.PG.KING || 0} carton
GOLD FRESH HEALTH PLUS EGG 高鮮蛋 - ${summary.PG.GOLD || 0} cartons

JB
KINGEGGS 高鮮帝王蛋- 0 carton
GOLD FRESH HEALTH PLUS EGG 高鮮蛋 - 0 cartons

KL 星期二到
PG 星期三到
JB 星期二到
`;
    };

    // Sections render in the order the user requested:
    //   PG Wholesale → PG Online → KL Wholesale → KL Online
    const _EGG_CHANNEL_SECTIONS = [
        { region: 'PG', channel: 'Wholesale', title: 'PG - Wholesale' },
        { region: 'PG', channel: 'Online',    title: 'PG - Online' },
        { region: 'KL', channel: 'Wholesale', title: 'KL - Wholesale' },
        { region: 'KL', channel: 'Online',    title: 'KL - Online' }
    ];

    // HTML version — renders each section as its own mini-table styled like
    // "Orders in this run" so the super admin can visually scan the exact
    // rows that rolled into each channel for the current week.
    const eggRenderChannelBreakdownHtml = (rows) => {
        return _EGG_CHANNEL_SECTIONS.map(sec => {
            const sectionRows = rows.filter(r => r.region === sec.region && r.channel === sec.channel);
            const totalGold = sectionRows.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity||0), 0);
            const totalKing = sectionRows.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity||0), 0);
            const body = sectionRows.length === 0 ?
                `<tr><td colspan="6" style="padding:10px;text-align:center;color:var(--gray-400);font-size:12px;">No orders</td></tr>` :
                sectionRows.map(r => {
                    const dateStr = r.order_date_parsed ? eggFormatDateShort(r.order_date_parsed) : '-';
                    return `
                        <tr style="border-top:1px solid var(--gray-200);">
                            <td style="padding:6px 8px;">${escapeHtml(r.agent_name || '-')}</td>
                            <td style="padding:6px 8px;font-size:12px;">${dateStr}</td>
                            <td style="padding:6px 8px;font-family:monospace;font-size:12px;">${escapeHtml(r.order_no || '-')}</td>
                            <td style="padding:6px 8px;font-family:monospace;font-size:12px;color:var(--gray-500);">${escapeHtml(r.product_code || '-')}</td>
                            <td style="padding:6px 8px;">${escapeHtml(r.product)}</td>
                            <td style="padding:6px 8px;text-align:right;">${r.quantity}</td>
                        </tr>
                    `;
                }).join('');
            return `
                <div style="margin-bottom:14px;">
                    <div style="display:flex;justify-content:space-between;align-items:center;background:#f8fafc;padding:8px 12px;border:1px solid var(--gray-200);border-bottom:none;border-top-left-radius:6px;border-top-right-radius:6px;">
                        <strong>${sec.title}</strong>
                        <span style="font-size:12px;color:var(--gray-600);">GOLD ${totalGold} • KING ${totalKing}</span>
                    </div>
                    <table style="width:100%;border-collapse:collapse;border:1px solid var(--gray-200);">
                        <thead>
                            <tr style="background:var(--gray-50);text-align:left;font-size:12px;">
                                <th scope="col" style="padding:6px 8px;">Agent</th>
                                <th scope="col" style="padding:6px 8px;">Order Date</th>
                                <th scope="col" style="padding:6px 8px;">Order No</th>
                                <th scope="col" style="padding:6px 8px;">Product Code</th>
                                <th scope="col" style="padding:6px 8px;">Product</th>
                                <th scope="col" style="padding:6px 8px;text-align:right;">Qty</th>
                            </tr>
                        </thead>
                        <tbody>${body}</tbody>
                    </table>
                </div>
            `;
        }).join('') + eggRenderGroupBreakdownHtml(eggGroupBreakdownFromRows(rows));
    };

    const eggRenderGroupBreakdownHtml = (byGroup) => {
        if (!byGroup || !Object.keys(byGroup).length) return '';
        const order = _EGG_WHOLESALE_GROUP_ORDER;
        const seen = new Set();
        const rows = [];
        for (const g of order) {
            if (byGroup[g] !== undefined) { rows.push([g, byGroup[g]]); seen.add(g); }
        }
        for (const [g, qty] of Object.entries(byGroup)) {
            if (!seen.has(g)) rows.push([g, qty]);
        }
        const cells = rows.map(([g, qty]) => `
            <div style="display:flex;justify-content:space-between;padding:7px 12px;border-bottom:1px solid var(--gray-100);">
                <span style="font-size:13px;">${escapeHtml(g)}</span>
                <strong style="font-size:13px;">${qty} cartons</strong>
            </div>`).join('');
        return `
            <div style="margin-bottom:14px;border:1px solid #d1fae5;border-radius:8px;overflow:hidden;">
                <div style="background:#ecfdf5;padding:8px 12px;font-weight:600;font-size:13px;color:#065f46;">
                    <i class="fas fa-layer-group"></i> Wholesales Group Summary
                </div>
                ${cells}
            </div>`;
    };

    // Text version — used for clipboard copy, .txt download, and run history.
    // Keeps the totals line + lists each row underneath so downstream tools
    // (e.g. WhatsApp, email) still have a readable per-row breakdown.
    const _EGG_WHOLESALE_GROUP_ORDER = [
        'KL Cheras', 'SG Puchong & Sunway', 'KL Kepong',
        'PG Center', 'PG Mainland', 'PG South'
    ];

    const eggGroupBreakdownFromRows = (rows) => {
        const byGroup = {};
        for (const r of rows) {
            if (r.channel !== 'Wholesale') continue;
            const g = r.group_name;
            if (g) byGroup[g] = (byGroup[g] || 0) + (Number(r.quantity) || 0);
        }
        return byGroup;
    };

    const eggRenderGroupBreakdownText = (byGroup) => {
        if (!byGroup || !Object.keys(byGroup).length) return '';
        let out = '\n=== Wholesales Group Summary ===\n';
        const seen = new Set();
        for (const g of _EGG_WHOLESALE_GROUP_ORDER) {
            if (byGroup[g] !== undefined) { out += `${g}: ${byGroup[g]} cartons\n`; seen.add(g); }
        }
        for (const [g, qty] of Object.entries(byGroup)) {
            if (!seen.has(g)) out += `${g}: ${qty} cartons\n`;
        }
        return out;
    };

    const eggRenderChannelBreakdownText = (rows) => {
        let out = '=== 批发 / 线上分类汇总 ===\n';
        for (const sec of _EGG_CHANNEL_SECTIONS) {
            const sectionRows = rows.filter(r => r.region === sec.region && r.channel === sec.channel);
            const totalGold = sectionRows.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity||0), 0);
            const totalKing = sectionRows.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity||0), 0);
            out += `\n${sec.title}: GOLD ${totalGold} cartons, KING ${totalKing} cartons\n`;
            for (const r of sectionRows) {
                const dateStr = r.order_date_parsed ? eggFormatDateShort(r.order_date_parsed) : '-';
                const agent = (r.agent_name || '-').padEnd(20).slice(0, 20);
                const date = dateStr.padEnd(10);
                const ordNo = (r.order_no || '-').padEnd(15).slice(0, 15);
                const code = (r.product_code || '').padEnd(12).slice(0, 12);
                const prod = (r.product || '').padEnd(6);
                out += `  ${agent} ${date} ${ordNo} ${code} ${prod} ${r.quantity}\n`;
            }
        }
        out += eggRenderGroupBreakdownText(eggGroupBreakdownFromRows(rows));
        return out;
    };

    // ── React full-JSX data payload (default-OFF, _reactEggJsxOn) ───────────
    // Build a PLAIN-SERIALIZABLE snapshot of EVERY tab's content (objects/arrays/
    // strings/numbers — never HTML strings) so EggPurchasingView can render the
    // whole view as REAL JSX. ONE source of truth: the same _eggState the legacy
    // eggRender*Tab fns read, plus the same DB reads they do (urgent/history/
    // config). Mirrors the legacy formulas/labels/sort/order 1:1 so flag-on looks
    // identical to flag-off. The async DB reads are awaited by the caller before
    // this runs (it receives them as args) so this fn itself never throws on I/O.
    //
    // Drag-drop, file parse, reconcile, commit, Sheets push all STAY in the chunk
    // handlers — the JSX path only wires onclick/onDrop to the existing app.* fns.
    const _eggChannelSectionData = (rows) => {
        // Mirror eggRenderChannelBreakdownHtml section computation as data.
        const sections = _EGG_CHANNEL_SECTIONS.map(sec => {
            const sectionRows = rows.filter(r => r.region === sec.region && r.channel === sec.channel);
            const totalGold = sectionRows.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity || 0), 0);
            const totalKing = sectionRows.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity || 0), 0);
            return {
                title: sec.title,
                totalGold,
                totalKing,
                rows: sectionRows.map(r => ({
                    agent_name: r.agent_name || '-',
                    dateStr: r.order_date_parsed ? eggFormatDateShort(r.order_date_parsed) : '-',
                    order_no: r.order_no || '-',
                    product_code: r.product_code || '-',
                    product: r.product,
                    quantity: r.quantity,
                })),
            };
        });
        // Mirror eggRenderGroupBreakdownHtml ordering.
        const byGroup = eggGroupBreakdownFromRows(rows);
        const seen = new Set();
        const groupRows = [];
        for (const g of _EGG_WHOLESALE_GROUP_ORDER) {
            if (byGroup[g] !== undefined) { groupRows.push({ group: g, qty: byGroup[g] }); seen.add(g); }
        }
        for (const [g, qty] of Object.entries(byGroup)) {
            if (!seen.has(g)) groupRows.push({ group: g, qty });
        }
        return { sections, groupRows };
    };

    // Builds the Run tab (3-phase wizard) state as plain data.
    const _eggBuildRunTabData = () => {
        const phase = _eggState.currentPhase || 1;
        const weekIso = eggFormatDateIso(_eggState.weekStartDate || eggGetCurrentMonday());
        const newRows = _eggState.newRows || [];
        const topUp = _eggState.lastWeekTopUp || { GOLD: 0, KING: 0 };
        const excludedKeys = Array.from(_eggState.excludedKeys || []);
        const excludedSet = new Set(excludedKeys);

        // Phase 2 candidate rows (same sort as eggRenderPhase2).
        const candidateRows = [...newRows].sort((a, b) => {
            const da = a.order_date_parsed || '￿';
            const db = b.order_date_parsed || '￿';
            if (da !== db) return da < db ? -1 : 1;
            return (a.order_no || '').localeCompare(b.order_no || '');
        }).map(r => ({
            unique_key: r.unique_key,
            pushed: excludedSet.has(r.unique_key),
            agent_name: r.agent_name || '-',
            dateStr: r.order_date_parsed ? eggFormatDateShort(r.order_date_parsed) : '-',
            order_no: r.order_no || '-',
            product: r.product,
            region: r.region,
            quantity: r.quantity,
            channel: r.channel,
        }));

        // Push-up counter (mirror eggPushUpCounterHtml).
        const pushed = newRows.filter(r => excludedSet.has(r.unique_key));
        const goldSum = pushed.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity || 0), 0);
        const kingSum = pushed.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity || 0), 0);

        // Previous run reference (mirror eggRenderPhase2 prev block).
        const prev = _eggState.prevRunOrders || [];
        const meta = _eggState.prevRunMeta;
        const prevGold = prev.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity || 0), 0);
        const prevKing = prev.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity || 0), 0);
        const sortedPrev = [...prev].sort((a, b) => {
            const da = a.order_date || '';
            const db = b.order_date || '';
            if (da !== db) return da.localeCompare(db);
            return (a.order_no || '').localeCompare(b.order_no || '');
        });
        const PREV_ROW_LIMIT = 10;
        const shownPrev = sortedPrev.slice(-PREV_ROW_LIMIT);
        const prevHiddenCount = Math.max(0, sortedPrev.length - shownPrev.length);

        return {
            phase,
            weekIso,
            csv: _eggState.csvFile ? { name: _eggState.csvFile.name, rows: _eggState.csvRows.length } : null,
            xlsx: _eggState.xlsxFile ? { name: _eggState.xlsxFile.name, rows: _eggState.xlsxRows.length } : null,
            ready: !!(_eggState.csvFile && _eggState.xlsxFile),
            topUp: { GOLD: Number(topUp.GOLD) || 0, KING: Number(topUp.KING) || 0 },
            candidateRows,
            newRowCount: newRows.length,
            pushUp: { goldSum, kingSum, goldTarget: Number(topUp.GOLD) || 0, kingTarget: Number(topUp.KING) || 0 },
            prev: {
                hasMeta: !!meta,
                weekLabel: (meta && meta.week_start_date) ? eggFormatDateShort(new Date(meta.week_start_date + 'T00:00:00')) : '',
                count: prev.length,
                goldTotal: prevGold,
                kingTotal: prevKing,
                hiddenCount: prevHiddenCount,
                shownCount: shownPrev.length,
                totalCount: sortedPrev.length,
                rows: shownPrev.map(r => ({
                    agent_name: r.agent_name || '-',
                    dateStr: r.order_date ? eggFormatDateShort(new Date(r.order_date)) : '-',
                    order_no: r.order_no || '-',
                    product: r.product || '-',
                    region: r.region || '-',
                    quantity: r.quantity,
                    channel: r.channel || '-',
                })),
            },
            stats: _eggState.stats || {},
            farmOrderText: _eggState.farmOrderText || '',
            channelBreakdown: _eggChannelSectionData((_eggState.newRows || []).filter(r => !excludedSet.has(r.unique_key))),
        };
    };

    // Top-level payload builder. `dbData` is { urgents, runs, config } the caller
    // fetched (async) before mount so this stays synchronous and pure.
    const buildEggIslandData = (dbData) => {
        const db = dbData || {};

        // ── URGENT tab (mirror eggRenderUrgentTab) ──
        const filter = _eggState.urgentFilter || 'active';
        const urgents = (db.urgents || []).slice().sort((a, b) =>
            String(b.week_start_date || '').localeCompare(String(a.week_start_date || '')));
        const filterFn = {
            active: u => ['pending', 'applied'].includes(u.status),
            resolved: u => ['reconciled', 'absorbed'].includes(u.status),
            stale: u => ['expired', 'cancelled'].includes(u.status),
            all: () => true,
        };
        const filtered = urgents.filter(filterFn[filter] || filterFn.all);
        const activeCount = urgents.filter(filterFn.active).length;
        const appliedCount = urgents.filter(u => u.status === 'applied').length;
        const urgentTab = {
            filter,
            activeCount,
            appliedCount,
            rows: filtered.map(u => ({
                id: u.id,
                week_start_date: u.week_start_date || '-',
                agent_name: u.agent_name || '-',
                product: u.product,
                region: u.region,
                quantity: u.quantity,
                channel: u.channel || 'Wholesale',
                status: u.status,
                notes: u.notes || '',
            })),
        };

        // ── HISTORY tab (mirror eggRenderHistoryTab) ──
        const runs = (db.runs || []).slice().sort((a, b) =>
            String(b.run_at || '').localeCompare(String(a.run_at || '')));
        const historyTab = {
            rows: runs.map(r => {
                const totals = r.totals || {};
                const tot = (totals.KL?.GOLD || 0) + (totals.KL?.KING || 0) + (totals.PG?.GOLD || 0) + (totals.PG?.KING || 0);
                return {
                    id: r.id,
                    runAtLabel: r.run_at ? new Date(r.run_at).toLocaleString() : '-',
                    week_start_date: r.week_start_date || '-',
                    files: `${r.csv_filename || '-'} / ${r.excel_filename || '-'}`,
                    rows_new: r.rows_new || 0,
                    rows_excluded: r.rows_excluded || 0,
                    cartons: tot,
                    run_by: r.run_by || '-',
                };
            }),
        };

        // ── CONFIG tab (mirror eggRenderConfigTab) ──
        const cfg = db.config || _eggState.config || eggDefaultConfig();
        const configTab = { json: JSON.stringify(cfg, null, 2) };

        return {
            activeTab: _eggState.currentTab || 'run',
            run: _eggBuildRunTabData(),
            urgent: urgentTab,
            history: historyTab,
            config: configTab,
        };
    };

    // Re-render the full-JSX island after a mutating handler. Rebuilds the payload
    // from the (already-updated) _eggState + fresh DB reads and remounts into the
    // captured container. No-op unless the JSX flag is on AND we have a container.
    // Self-contained: never touches the legacy #egg-tab-content path.
    const eggRerenderJsx = async () => {
        if (!_reactEggJsxOn()) return;
        const container = _eggState._lastContainer;
        if (!container || !(window.CRMReact && typeof window.CRMReact.mountEggPurchasing === 'function')) return;
        try {
            await showEggPurchasingView(container);
        } catch (e) {
            console.warn('[egg] JSX re-render failed:', e && e.message);
        }
    };

    // Refresh a tab after a mutating handler, working on BOTH render paths.
    // On the legacy/scaffold path the #egg-tab-content host exists → re-render it
    // in place (byte-identical to the old `eggRenderXTab(getElementById(...))`
    // call). On the full-JSX default path that host does NOT exist — calling the
    // legacy renderer with a null host would throw (`Cannot set properties of
    // null`) and fire a false failure toast even though the write succeeded, and
    // the JSX list would never refresh. Guarding the host and firing
    // eggRerenderJsx() fixes both: no throw when the host is absent, and the JSX
    // island remounts from fresh state. `renderFn` is one of the eggRenderXTab
    // functions; the JSX rerender ignores it and rebuilds all tabs from state.
    const eggRerenderTab = async (renderFn) => {
        const host = document.getElementById('egg-tab-content');
        if (host && typeof renderFn === 'function') {
            await renderFn(host);
        }
        await eggRerenderJsx();
    };

    // ==================== MAIN VIEW RENDERER ====================

    // Pure builder for the legacy (non-React) Egg Purchasing shell: header + tab
    // bar + the empty #egg-tab-content host that eggSwitchTab() later fills.
    // Fully static markup (no interpolation) — extracted from showEggPurchasingView
    // verbatim so the produced HTML string is byte-identical to the inline literal.
    const buildEggPurchasingShell = () => `
            <div class="egg-purchasing-view" style="padding:24px;">
                <div class="egg-header" style="display:flex;align-items:center;justify-content:space-between;margin-bottom:20px;">
                    <div>
                        <h1 style="margin:0;display:flex;align-items:center;gap:10px;">
                            <i class="fas fa-egg" style="color:#f59e0b;"></i> Egg Purchasing
                        </h1>
                        <div style="color:var(--gray-500);font-size:13px;margin-top:4px;">
                            Weekly farm order generation. Super Admin only.
                        </div>
                    </div>
                    <button class="btn secondary" onclick="app.eggRefresh()">
                        <i class="fas fa-sync-alt"></i> Refresh
                    </button>
                </div>

                <div class="egg-tabs" style="display:flex;gap:4px;border-bottom:2px solid var(--gray-200);margin-bottom:20px;">
                    <button class="egg-tab-btn active" data-tab="run" onclick="app.eggSwitchTab('run')"
                        style="padding:12px 20px;background:none;border:none;border-bottom:3px solid #f59e0b;font-weight:600;cursor:pointer;color:#f59e0b;">
                        <i class="fas fa-play-circle"></i> Run This Week
                    </button>
                    <button class="egg-tab-btn" data-tab="urgent" onclick="app.eggSwitchTab('urgent')"
                        style="padding:12px 20px;background:none;border:none;border-bottom:3px solid transparent;font-weight:600;cursor:pointer;color:var(--gray-600);">
                        <i class="fas fa-bolt"></i> Urgent Orders
                    </button>
                    <button class="egg-tab-btn" data-tab="history" onclick="app.eggSwitchTab('history')"
                        style="padding:12px 20px;background:none;border:none;border-bottom:3px solid transparent;font-weight:600;cursor:pointer;color:var(--gray-600);">
                        <i class="fas fa-history"></i> Run History
                    </button>
                    <button class="egg-tab-btn" data-tab="config" onclick="app.eggSwitchTab('config')"
                        style="padding:12px 20px;background:none;border:none;border-bottom:3px solid transparent;font-weight:600;cursor:pointer;color:var(--gray-600);">
                        <i class="fas fa-cog"></i> Configuration
                    </button>
                </div>

                <div id="egg-tab-content"></div>
            </div>
        `;

    const showEggPurchasingView = async (container) => {
        _state.cv = 'egg_purchasing';
        if (!isSystemAdmin(_state.cu)) {
            container.innerHTML = `<div class="placeholder-view"><h1>Access Denied</h1><p>Egg Purchasing is restricted to Super Admin only.</p></div>`;
            return;
        }
        await eggLoadConfig();

        // React scaffold-shell — island renders shell; chunk eggSwitchTab() (via
        // useEffect onReady) fills #egg-tab-content (wizard/file-IO/reconcile unchanged).
        if (_reactEggOn()) {
            try {
                const _eggTabs = [
                    { key: 'run', label: 'Run This Week', icon: 'fa-play-circle' },
                    { key: 'urgent', label: 'Urgent Orders', icon: 'fa-bolt' },
                    { key: 'history', label: 'Run History', icon: 'fa-history' },
                    { key: 'config', label: 'Configuration', icon: 'fa-cog' },
                ];
                const _eggTab = _eggState.currentTab || 'run';

                // NEW full-JSX path (default-OFF, _reactEggJsxOn). Build a plain
                // structured payload of ALL tabs; when present, EggPurchasingView
                // renders REAL JSX (React-state tab switching) and we SUPPRESS the
                // by-id #egg-tab-content fill (the JSX view owns the DOM). Built in
                // try/catch: on ANY throw we leave _islandData null and fall back to
                // the EXACT existing scaffold-shell onReady fill below — byte-for-
                // byte the current behavior, never a blank screen. When the flag is
                // OFF, _islandData stays null and nothing about the existing path
                // changes. Remember the container so mutating handlers can re-render.
                _eggState._lastContainer = container;
                let _islandData;
                if (_reactEggJsxOn()) {
                    try {
                        const [_urgents, _runs] = await Promise.all([
                            AppDataStore.query('egg_urgent_orders', {}).catch(() => []),
                            AppDataStore.query('egg_run_history', {}).catch(() => []),
                        ]);
                        _islandData = buildEggIslandData({ urgents: _urgents || [], runs: _runs || [], config: _eggState.config });
                    } catch (e) {
                        _islandData = undefined;
                        console.warn('[egg] JSX payload build failed, using by-id fill fallback:', e && e.message);
                    }
                }

                container.innerHTML = '<div id="egg-react-root"></div>';
                window.CRMReact.mountEggPurchasing(document.getElementById('egg-react-root'), {
                    tabs: _eggTabs, activeTab: _eggTab,
                    data: _islandData || undefined,
                    // JSX path owns the DOM → no by-id fill (no-op onReady). Off /
                    // fallback path keeps the EXACT existing eggSwitchTab fill.
                    onReady: _islandData ? (() => {}) : (() => { eggSwitchTab(_eggTab); }),
                });
                return;
            } catch (e) {
                console.warn('[egg] island mount failed, falling back to legacy:', e && e.message);
                // fall through to the legacy render below
            }
        }

        container.innerHTML = buildEggPurchasingShell();

        await eggSwitchTab(_eggState.currentTab || 'run');
    };

    const eggSwitchTab = async (tab) => {
        _eggState.currentTab = tab;
        document.querySelectorAll('.egg-tab-btn').forEach(btn => {
            const isActive = btn.getAttribute('data-tab') === tab;
            btn.classList.toggle('active', isActive);
            btn.style.borderBottomColor = isActive ? '#f59e0b' : 'transparent';
            btn.style.color = isActive ? '#f59e0b' : 'var(--gray-600)';
        });
        const host = document.getElementById('egg-tab-content');
        if (!host) return;
        if (tab === 'run') await eggRenderRunTab(host);
        else if (tab === 'urgent') await eggRenderUrgentTab(host);
        else if (tab === 'history') await eggRenderHistoryTab(host);
        else if (tab === 'config') await eggRenderConfigTab(host);
    };

    const eggRefresh = async () => {
        const host = document.getElementById('egg-tab-content');
        if (host) await eggSwitchTab(_eggState.currentTab);
    };

    // ==================== TAB 1 — RUN (3-PHASE WIZARD) ====================

    const eggRenderRunTab = async (host) => {
        const phase = _eggState.currentPhase || 1;
        if (phase === 1) return eggRenderPhase1(host);
        if (phase === 2) return eggRenderPhase2(host);
        if (phase === 3) return eggRenderPhase3(host);
    };

    const eggRenderPhase1 = (host) => {
        const weekIso = eggFormatDateIso(_eggState.weekStartDate || eggGetCurrentMonday());
        const csvInfo = _eggState.csvFile ? `<div style="color:#059669;"><i class="fas fa-check-circle"></i> ${escapeHtml(_eggState.csvFile.name)} — ${_eggState.csvRows.length} rows</div>` : '<div style="color:var(--gray-400);">No file selected</div>';
        const xlsInfo = _eggState.xlsxFile ? `<div style="color:#059669;"><i class="fas fa-check-circle"></i> ${escapeHtml(_eggState.xlsxFile.name)} — ${_eggState.xlsxRows.length} rows</div>` : '<div style="color:var(--gray-400);">No file selected</div>';
        const ready = _eggState.csvFile && _eggState.xlsxFile;

        host.innerHTML = `
            <div class="egg-phase-banner" style="display:flex;gap:8px;margin-bottom:20px;">
                <div style="flex:1;padding:10px;background:#fef3c7;border-left:4px solid #f59e0b;border-radius:6px;">
                    <strong>Phase 1:</strong> Upload
                </div>
                <div style="flex:1;padding:10px;background:var(--gray-100);border-left:4px solid var(--gray-300);border-radius:6px;color:var(--gray-500);">
                    <strong>Phase 2:</strong> Reconcile
                </div>
                <div style="flex:1;padding:10px;background:var(--gray-100);border-left:4px solid var(--gray-300);border-radius:6px;color:var(--gray-500);">
                    <strong>Phase 3:</strong> Preview &amp; Commit
                </div>
            </div>

            <div style="background:white;padding:24px;border-radius:12px;border:1px solid var(--gray-200);">
                <h3 style="margin-top:0;">Upload Invoice Files</h3>
                <p style="color:var(--gray-500);font-size:13px;">Drop both files below. CSV is the Order Tracking Details export, XLSX is the Download Egg Order file.</p>

                <div style="margin:16px 0;">
                    <label style="font-weight:600;display:block;margin-bottom:6px;">Week Start (Monday)</label>
                    <input type="date" id="egg-week-start" value="${weekIso}" onchange="app.eggSetWeekStart(this.value)"
                        style="padding:8px 12px;border:1px solid var(--gray-300);border-radius:6px;font-size:14px;">
                    <span style="color:var(--gray-500);font-size:12px;margin-left:10px;">This identifies which urgent orders to pull for reconciliation.</span>
                </div>

                <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-top:16px;">
                    <div class="egg-drop-zone" id="egg-drop-csv" style="padding:24px;border:2px dashed var(--gray-300);border-radius:8px;text-align:center;cursor:pointer;"
                        ondragover="event.preventDefault();this.style.borderColor='#f59e0b';"
                        ondragleave="this.style.borderColor='var(--gray-300)';"
                        ondrop="event.preventDefault();this.style.borderColor='var(--gray-300)';app.eggHandleCsvDrop(event);"
                        onclick="document.getElementById('egg-csv-input').click();">
                        <i class="fas fa-file-csv" style="font-size:32px;color:#10b981;margin-bottom:10px;"></i>
                        <div style="font-weight:600;">Order Tracking Details (.csv)</div>
                        <div style="color:var(--gray-500);font-size:12px;margin:6px 0;">Drop file here or click to browse</div>
                        ${csvInfo}
                        <input type="file" id="egg-csv-input" accept=".csv" style="display:none;" onchange="app.eggHandleCsvInput(event)">
                    </div>

                    <div class="egg-drop-zone" id="egg-drop-xlsx" style="padding:24px;border:2px dashed var(--gray-300);border-radius:8px;text-align:center;cursor:pointer;"
                        ondragover="event.preventDefault();this.style.borderColor='#f59e0b';"
                        ondragleave="this.style.borderColor='var(--gray-300)';"
                        ondrop="event.preventDefault();this.style.borderColor='var(--gray-300)';app.eggHandleXlsxDrop(event);"
                        onclick="document.getElementById('egg-xlsx-input').click();">
                        <i class="fas fa-file-excel" style="font-size:32px;color:#059669;margin-bottom:10px;"></i>
                        <div style="font-weight:600;">Download Egg Order (.xlsx)</div>
                        <div style="color:var(--gray-500);font-size:12px;margin:6px 0;">Drop file here or click to browse</div>
                        ${xlsInfo}
                        <input type="file" id="egg-xlsx-input" accept=".xlsx,.xls" style="display:none;" onchange="app.eggHandleXlsxInput(event)">
                    </div>
                </div>

                <div style="margin-top:24px;display:flex;justify-content:space-between;align-items:center;">
                    <button class="btn secondary" onclick="app.eggResetRun()">
                        <i class="fas fa-redo"></i> Reset
                    </button>
                    <button class="btn primary" onclick="app.eggGoToPhase2()" ${ready ? '' : 'disabled'}
                        style="${ready ? '' : 'opacity:0.5;cursor:not-allowed;'}">
                        Next: Reconcile <i class="fas fa-arrow-right"></i>
                    </button>
                </div>
            </div>
        `;
    };

    const eggSetWeekStart = (iso) => {
        // Parse as LOCAL date (not UTC) to avoid off-by-day bugs in non-UTC+8 timezones.
        // `new Date("2026-04-13")` is UTC midnight; we want local midnight instead.
        if (!iso) { _eggState.weekStartDate = null; return; }
        const parts = String(iso).split('-').map(Number);
        if (parts.length !== 3 || parts.some(isNaN)) { _eggState.weekStartDate = null; return; }
        _eggState.weekStartDate = new Date(parts[0], parts[1] - 1, parts[2]);
    };

    const eggHandleCsvDrop = async (event) => {
        const file = event.dataTransfer.files[0];
        if (file) await eggLoadCsvFile(file);
    };
    const eggHandleCsvInput = async (event) => {
        const file = event.target.files[0];
        if (file) await eggLoadCsvFile(file);
    };
    const eggLoadCsvFile = async (file) => {
        if (!file.name.toLowerCase().endsWith('.csv')) {
            UI.toast.error('Please drop a .csv file');
            // Reset file input so user can re-pick
            const inp = document.getElementById('egg-csv-input'); if (inp) inp.value = '';
            return;
        }
        try {
            const { headers, rows } = await eggParseCsv(file);
            _eggState.csvFile = file;
            _eggState.csvHeaders = headers;
            _eggState.csvRows = rows;
            UI.toast.success(`CSV loaded: ${rows.length} rows`);
            await eggRerenderTab(eggRenderRunTab);
        } catch (err) {
            UI.toast.error('CSV parse failed: ' + err.message);
            const inp = document.getElementById('egg-csv-input'); if (inp) inp.value = '';
        }
    };

    const eggHandleXlsxDrop = async (event) => {
        const file = event.dataTransfer.files[0];
        if (file) await eggLoadXlsxFile(file);
    };
    const eggHandleXlsxInput = async (event) => {
        const file = event.target.files[0];
        if (file) await eggLoadXlsxFile(file);
    };
    const eggLoadXlsxFile = async (file) => {
        const lower = file.name.toLowerCase();
        if (!lower.endsWith('.xlsx') && !lower.endsWith('.xls')) {
            UI.toast.error('Please drop a .xlsx file');
            const inp = document.getElementById('egg-xlsx-input'); if (inp) inp.value = '';
            return;
        }
        try {
            const { headers, rows } = await eggParseXlsx(file);
            _eggState.xlsxFile = file;
            _eggState.xlsxHeaders = headers;
            _eggState.xlsxRows = rows;
            UI.toast.success(`XLSX loaded: ${rows.length} rows`);
            await eggRerenderTab(eggRenderRunTab);
        } catch (err) {
            UI.toast.error('XLSX parse failed: ' + err.message);
            const inp = document.getElementById('egg-xlsx-input'); if (inp) inp.value = '';
        }
    };

    const eggResetRun = () => {
        _eggState.csvFile = null; _eggState.csvRows = []; _eggState.csvHeaders = [];
        _eggState.xlsxFile = null; _eggState.xlsxRows = []; _eggState.xlsxHeaders = [];
        _eggState.normalizedRows = [];
        _eggState.newRows = [];
        _eggState.urgentOrders = [];
        _eggState.matches = [];
        _eggState.excludedKeys = new Set();
        _eggState.excludedToUrgent = {};
        _eggState.lastWeekTopUp = { GOLD: 0, KING: 0 };
        _eggState.farmOrderText = '';
        _eggState.channelBreakdownText = '';
        _eggState.channelBreakdownHtml = '';
        _eggState.stats = {};
        _eggState.droppedDupes = 0;
        _eggState.droppedFutureDated = 0;
        _eggState.currentPhase = 1;
        // Reset any live file inputs so the same file can be re-picked
        const csvInp = document.getElementById('egg-csv-input'); if (csvInp) csvInp.value = '';
        const xlsInp = document.getElementById('egg-xlsx-input'); if (xlsInp) xlsInp.value = '';
        eggRerenderTab(eggRenderRunTab);
    };

    const eggGoToPhase2 = async () => {
        if (!_eggState.csvFile || !_eggState.xlsxFile) {
            UI.toast.error('Upload both files first');
            return;
        }
        UI.toast.info('Processing rows...');

        // Defensive: ensure config is loaded. Normally showEggPurchasingView loads
        // it on tab entry, but race conditions during page init can leave it null.
        if (!_eggState.config) await eggLoadConfig();

        // Normalize and filter
        const csvNorm = _eggState.csvRows.map(eggNormalizeCsvRow);
        const xlsNorm = _eggState.xlsxRows.map(eggNormalizeXlsxRow);
        const combined = [...csvNorm, ...xlsNorm];
        const config = _eggState.config;
        const processed = eggProcessRows(combined, config);

        // Dedup against history
        const newRows = await eggDedupAgainstHistory(processed);
        _eggState.normalizedRows = processed;
        _eggState.newRows = newRows;

        // Fetch previous run's orders for the reference panel in Phase 2
        try {
            const runs = await AppDataStore.query('egg_run_history', {}) || [];
            const currentWeekIso = eggFormatDateIso(_eggState.weekStartDate || eggGetCurrentMonday());
            const prevRun = runs
                .filter(r => r.week_start_date && r.week_start_date < currentWeekIso)
                .sort((a, b) => {
                    const wk = (b.week_start_date || '').localeCompare(a.week_start_date || '');
                    if (wk !== 0) return wk;
                    // Same week committed more than once — newest run_at wins so the
                    // reference panel reflects the latest re-commit, not a stale version.
                    return String(b.run_at || '').localeCompare(String(a.run_at || ''));
                })[0];
            if (prevRun) {
                const prevOrders = await AppDataStore.query('egg_processed_orders', { run_id: prevRun.id }) || [];
                prevOrders.sort((a, b) => (a.order_date || '').localeCompare(b.order_date || ''));
                _eggState.prevRunOrders = prevOrders.filter(h => !h.excluded_reason);
                _eggState.prevRunMeta = prevRun;
            } else {
                _eggState.prevRunOrders = [];
                _eggState.prevRunMeta = null;
            }
        } catch (e) {
            _eggState.prevRunOrders = [];
            _eggState.prevRunMeta = null;
        }

        // Simplified flow: no more urgent-order reconciliation. User just enters
        // last-week top-up amounts and ticks the rows that were placed last week.
        _eggState.urgentOrders = [];
        _eggState.matches = [];
        _eggState.excludedKeys = new Set();
        _eggState.excludedToUrgent = {};

        _eggState.currentPhase = 2;
        await eggRerenderTab(eggRenderRunTab);
    };

    const eggRenderPhase2 = (host) => {
        const newRows = _eggState.newRows || [];
        const topUp = _eggState.lastWeekTopUp || { GOLD: 0, KING: 0 };

        const candidateRowsHtml = newRows.length === 0 ?
            `<div style="padding:16px;text-align:center;color:var(--gray-500);">No new orders to reconcile.</div>` :
            `<table style="width:100%;border-collapse:collapse;">
                <thead>
                    <tr style="background:var(--gray-50);text-align:left;">
                        <th scope="col" style="padding:8px;width:40px;"></th>
                        <th scope="col" style="padding:8px;">Agent</th>
                        <th scope="col" style="padding:8px;">Order Date</th>
                        <th scope="col" style="padding:8px;">Order No</th>
                        <th scope="col" style="padding:8px;">Product</th>
                        <th scope="col" style="padding:8px;">Region</th>
                        <th scope="col" style="padding:8px;text-align:right;">Qty</th>
                        <th scope="col" style="padding:8px;">Channel</th>
                        <th scope="col" style="padding:8px;">Match</th>
                    </tr>
                </thead>
                <tbody>
                ${[...newRows].sort((a, b) => {
                    const da = a.order_date_parsed || '￿';
                    const db = b.order_date_parsed || '￿';
                    if (da !== db) return da < db ? -1 : 1;
                    return (a.order_no || '').localeCompare(b.order_no || '');
                }).map(r => {
                    const pushed = _eggState.excludedKeys.has(r.unique_key);
                    const checked = pushed ? 'checked' : '';
                    const rowStyle = pushed ? 'background:#fef2f2;' : '';
                    const matchBadge = pushed ?
                        `<span style="background:#dc2626;color:white;padding:2px 8px;border-radius:10px;font-size:11px;">PUSHED UP</span>` :
                        '-';
                    const dateStr = r.order_date_parsed ? eggFormatDateShort(r.order_date_parsed) : '-';
                    // unique_key embeds order_no taken verbatim from the uploaded file —
                    // escape it for the HTML attribute (data-egg-key) and the inline
                    // onchange JS-string arg so a quote in the order number can't break
                    // the attribute / terminate the handler string or inject app.* calls.
                    const keyAttr = escapeHtml(r.unique_key || '');
                    const keyJs = UI.escJsAttr(String(r.unique_key || ''));
                    return `
                        <tr data-egg-key="${keyAttr}" style="border-top:1px solid var(--gray-200);${rowStyle}">
                            <td style="padding:8px;"><input type="checkbox" ${checked} onchange="app.eggToggleExclude('${keyJs}')"></td>
                            <td style="padding:8px;">${escapeHtml(r.agent_name || '-')}</td>
                            <td style="padding:8px;font-size:12px;">${dateStr}</td>
                            <td style="padding:8px;font-family:monospace;font-size:12px;">${escapeHtml(r.order_no || '-')}</td>
                            <td style="padding:8px;">${escapeHtml(r.product)}</td>
                            <td style="padding:8px;">${escapeHtml(r.region)}</td>
                            <td style="padding:8px;text-align:right;">${r.quantity}</td>
                            <td style="padding:8px;">${escapeHtml(r.channel)}</td>
                            <td class="egg-match-cell" style="padding:8px;">${matchBadge}</td>
                        </tr>
                    `;
                }).join('')}
                </tbody>
            </table>`;

        host.innerHTML = `
            <div class="egg-phase-banner" style="display:flex;gap:8px;margin-bottom:20px;">
                <div style="flex:1;padding:10px;background:var(--gray-100);border-left:4px solid var(--gray-300);border-radius:6px;color:var(--gray-500);">
                    <strong>Phase 1:</strong> Upload
                </div>
                <div style="flex:1;padding:10px;background:#fef3c7;border-left:4px solid #f59e0b;border-radius:6px;">
                    <strong>Phase 2:</strong> Reconcile
                </div>
                <div style="flex:1;padding:10px;background:var(--gray-100);border-left:4px solid var(--gray-300);border-radius:6px;color:var(--gray-500);">
                    <strong>Phase 3:</strong> Preview &amp; Commit
                </div>
            </div>

            <div style="background:#fffbeb;border:1px solid #f59e0b;border-radius:8px;padding:16px;margin-bottom:20px;">
                <strong><i class="fas fa-question-circle"></i> Last Week Top-Up</strong>
                <div style="color:var(--gray-600);font-size:13px;margin:6px 0 12px 0;">
                    Did you add any ad-hoc orders last week that bypassed the normal sales flow? Enter the quantities you added, then tick the rows below that were actually placed last week so they're excluded from this week's farm order.
                </div>
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;max-width:480px;">
                    <div>
                        <label style="font-weight:600;display:block;margin-bottom:4px;font-size:13px;">GOLD (cartons)</label>
                        <input type="number" min="0" step="1" value="${topUp.GOLD || 0}"
                            oninput="app.eggSetLastWeekTopUp('GOLD', this.value)"
                            style="width:100%;padding:8px 12px;border:1px solid var(--gray-300);border-radius:6px;font-size:14px;">
                    </div>
                    <div>
                        <label style="font-weight:600;display:block;margin-bottom:4px;font-size:13px;">KIN / KING (cartons)</label>
                        <input type="number" min="0" step="1" value="${topUp.KING || 0}"
                            oninput="app.eggSetLastWeekTopUp('KING', this.value)"
                            style="width:100%;padding:8px 12px;border:1px solid var(--gray-300);border-radius:6px;font-size:14px;">
                    </div>
                </div>
                <div id="egg-pushup-counter" style="margin-top:12px;font-size:13px;">${eggPushUpCounterHtml()}</div>
            </div>

            ${(() => {
                const prev = _eggState.prevRunOrders || [];
                const meta = _eggState.prevRunMeta;
                const hasMeta = !!meta;
                const weekLabel = (hasMeta && meta.week_start_date) ? eggFormatDateShort(new Date(meta.week_start_date + 'T00:00:00')) : '';
                const goldTotal = prev.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity || 0), 0);
                const kingTotal = prev.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity || 0), 0);
                const sortedPrev = [...prev].sort((a, b) => {
                    const da = a.order_date || '';
                    const db = b.order_date || '';
                    if (da !== db) return da.localeCompare(db);
                    return (a.order_no || '').localeCompare(b.order_no || '');
                });
                const PREV_ROW_LIMIT = 10;
                const shownPrev = sortedPrev.slice(-PREV_ROW_LIMIT);
                const hiddenCount = Math.max(0, sortedPrev.length - shownPrev.length);
                const rows = shownPrev.map(r => `
                    <tr style="border-top:1px solid var(--gray-100);">
                        <td style="padding:6px 8px;">${escapeHtml(r.agent_name || '-')}</td>
                        <td style="padding:6px 8px;font-size:12px;">${r.order_date ? eggFormatDateShort(new Date(r.order_date)) : '-'}</td>
                        <td style="padding:6px 8px;font-family:monospace;font-size:12px;">${escapeHtml(r.order_no || '-')}</td>
                        <td style="padding:6px 8px;">${escapeHtml(r.product || '-')}</td>
                        <td style="padding:6px 8px;">${escapeHtml(r.region || '-')}</td>
                        <td style="padding:6px 8px;text-align:right;">${r.quantity}</td>
                        <td style="padding:6px 8px;">${escapeHtml(r.channel || '-')}</td>
                    </tr>`).join('');
                const titleText = hasMeta ? `Last Week's Orders — Week of ${weekLabel}` : `Last Week's Orders`;
                const shownNote = hiddenCount > 0 ? ` &nbsp;•&nbsp; showing last ${shownPrev.length} of ${sortedPrev.length}` : '';
                const headerSubtitle = hasMeta
                    ? `${prev.length} orders &nbsp;•&nbsp; GOLD ${goldTotal} &nbsp;•&nbsp; KING ${kingTotal}${shownNote}`
                    : `No previous run found — this is your first reconcile.`;
                const bodyContent = (hasMeta && prev.length > 0)
                    ? `<table style="width:100%;border-collapse:collapse;font-size:13px;">
                            <thead>
                                <tr style="background:var(--gray-50);text-align:left;">
                                    <th scope="col" style="padding:6px 8px;">Agent</th>
                                    <th scope="col" style="padding:6px 8px;">Order Date</th>
                                    <th scope="col" style="padding:6px 8px;">Order No</th>
                                    <th scope="col" style="padding:6px 8px;">Product</th>
                                    <th scope="col" style="padding:6px 8px;">Region</th>
                                    <th scope="col" style="padding:6px 8px;text-align:right;">Qty</th>
                                    <th scope="col" style="padding:6px 8px;">Channel</th>
                                </tr>
                            </thead>
                            <tbody>${rows}</tbody>
                        </table>`
                    : `<div style="padding:16px;text-align:center;color:var(--gray-500);font-size:13px;">
                            Once you commit your first weekly run, last week's orders will appear here for reference.
                        </div>`;
                return `
                <div style="background:white;border:1px solid var(--gray-200);border-radius:12px;margin-bottom:20px;">
                    <div onclick="this.parentElement.querySelector('.egg-hist-body').style.display=this.parentElement.querySelector('.egg-hist-body').style.display==='none'?'block':'none';this.querySelector('.egg-hist-chevron').style.transform=this.parentElement.querySelector('.egg-hist-body').style.display==='none'?'rotate(0deg)':'rotate(180deg)';"
                        style="display:flex;justify-content:space-between;align-items:center;padding:14px 20px;cursor:pointer;user-select:none;">
                        <div>
                            <strong>${titleText}</strong>
                            <span style="margin-left:12px;font-size:12px;color:var(--gray-500);">${headerSubtitle}</span>
                        </div>
                        <i class="fas fa-chevron-down egg-hist-chevron" style="transition:transform 0.2s;transform:rotate(180deg);color:var(--gray-400);"></i>
                    </div>
                    <div class="egg-hist-body" style="display:block;border-top:1px solid var(--gray-200);overflow-x:auto;">
                        ${bodyContent}
                    </div>
                </div>`;
            })()}

            <div style="background:white;padding:20px;border-radius:12px;border:1px solid var(--gray-200);">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
                    <h3 style="margin:0;">Orders in this run (${newRows.length} new rows after dedup)</h3>
                    <div>
                        <button class="btn secondary btn-sm" onclick="app.eggClearExclusions()">Clear push-ups</button>
                    </div>
                </div>
                <div style="color:var(--gray-500);font-size:12px;margin-bottom:8px;">
                    Tick a row to <strong>push it up</strong> — marks it as already placed last week and excludes it from this week's farm order.
                </div>
                ${candidateRowsHtml}
            </div>

            <div style="margin-top:20px;display:flex;justify-content:space-between;">
                <button class="btn secondary" onclick="app.eggGoToPhase1()">
                    <i class="fas fa-arrow-left"></i> Back to Upload
                </button>
                <button class="btn primary" onclick="app.eggGoToPhase3()">
                    Next: Preview Farm Order <i class="fas fa-arrow-right"></i>
                </button>
            </div>
        `;
    };

    // Compute the live "pushed up so far" counter compared against user's top-up input
    const eggPushUpCounterHtml = () => {
        const newRows = _eggState.newRows || [];
        const topUp = _eggState.lastWeekTopUp || { GOLD: 0, KING: 0 };
        const pushed = newRows.filter(r => _eggState.excludedKeys.has(r.unique_key));
        const goldSum = pushed.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity||0), 0);
        const kingSum = pushed.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity||0), 0);
        const goldTarget = Number(topUp.GOLD) || 0;
        const kingTarget = Number(topUp.KING) || 0;
        const goldColor = goldSum === goldTarget ? '#059669' : '#b45309';
        const kingColor = kingSum === kingTarget ? '#059669' : '#b45309';
        const goldIcon = goldSum === goldTarget ? '<i class="fas fa-check-circle"></i>' : '<i class="fas fa-exclamation-triangle"></i>';
        const kingIcon = kingSum === kingTarget ? '<i class="fas fa-check-circle"></i>' : '<i class="fas fa-exclamation-triangle"></i>';
        return `
            <span style="color:var(--gray-600);">Pushed up so far:</span>
            <span style="color:${goldColor};font-weight:600;margin-left:8px;">${goldIcon} GOLD ${goldSum} / ${goldTarget}</span>
            <span style="color:${kingColor};font-weight:600;margin-left:12px;">${kingIcon} KING ${kingSum} / ${kingTarget}</span>
        `;
    };

    // Persist the user's last-week top-up input and refresh the live counter
    // without re-rendering (which would lose input focus).
    const eggSetLastWeekTopUp = (product, val) => {
        _eggState.lastWeekTopUp = _eggState.lastWeekTopUp || { GOLD: 0, KING: 0 };
        _eggState.lastWeekTopUp[product] = Number(val) || 0;
        const counter = document.getElementById('egg-pushup-counter');
        if (counter) counter.innerHTML = eggPushUpCounterHtml();
    };

    const eggGoToPhase1 = async () => {
        _eggState.currentPhase = 1;
        await eggRerenderTab(eggRenderRunTab);
    };

    const eggToggleExclude = (uniqueKey) => {
        if (_eggState.excludedKeys.has(uniqueKey)) {
            _eggState.excludedKeys.delete(uniqueKey);
        } else {
            _eggState.excludedKeys.add(uniqueKey);
        }
        // Partial DOM update — avoids full re-render so the user's scroll
        // position and the top-up input focus are preserved.
        // CSS.escape the key (built from raw file order_no) so a quote/bracket
        // in the value can't break the attribute selector and silently no-op.
        const escSel = (typeof CSS !== 'undefined' && CSS.escape)
            ? CSS.escape(String(uniqueKey))
            : String(uniqueKey).replace(/["\\]/g, '\\$&');
        const tr = document.querySelector(`tr[data-egg-key="${escSel}"]`);
        if (tr) {
            const pushed = _eggState.excludedKeys.has(uniqueKey);
            tr.style.background = pushed ? '#fef2f2' : '';
            const cell = tr.querySelector('.egg-match-cell');
            if (cell) {
                cell.innerHTML = pushed
                    ? '<span style="background:#dc2626;color:white;padding:2px 8px;border-radius:10px;font-size:11px;">PUSHED UP</span>'
                    : '-';
            }
        }
        const counter = document.getElementById('egg-pushup-counter');
        if (counter) counter.innerHTML = eggPushUpCounterHtml();
    };

    const eggClearExclusions = async () => {
        _eggState.excludedKeys = new Set();
        _eggState.excludedToUrgent = {};
        await eggRerenderTab(eggRenderRunTab);
    };

    const eggGoToPhase3 = async () => {
        // Tally check — compare pushed-up quantities against the last-week
        // top-up the user entered. Mismatch = warning popup only; we still
        // proceed to Phase 3 so the user is never blocked.
        const topUp = _eggState.lastWeekTopUp || { GOLD: 0, KING: 0 };
        const pushed = (_eggState.newRows || []).filter(r => _eggState.excludedKeys.has(r.unique_key));
        const pushedGold = pushed.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity||0), 0);
        const pushedKing = pushed.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity||0), 0);
        const targetGold = Number(topUp.GOLD) || 0;
        const targetKing = Number(topUp.KING) || 0;
        if (pushedGold !== targetGold || pushedKing !== targetKing) {
            const diffGold = pushedGold - targetGold;
            const diffKing = pushedKing - targetKing;
            const sign = (n) => n > 0 ? `+${n}` : `${n}`;
            alert(
                `Heads up — the pushed-up quantities don't tally with the top-up you entered:\n\n` +
                `GOLD: pushed up ${pushedGold}, top-up was ${targetGold} (diff: ${sign(diffGold)})\n` +
                `KING: pushed up ${pushedKing}, top-up was ${targetKing} (diff: ${sign(diffKing)})\n\n` +
                `You can still proceed — this is just a reminder.`
            );
        }

        // Build final row set with exclusions applied
        const keep = (_eggState.newRows || []).filter(r => !_eggState.excludedKeys.has(r.unique_key));
        const summary = eggAggregate(keep);
        _eggState.farmOrderText = eggRenderFarmOrderText(summary, new Date());
        _eggState.channelBreakdownHtml = eggRenderChannelBreakdownHtml(keep);
        _eggState.channelBreakdownText = eggRenderChannelBreakdownText(keep);
        _eggState.stats = {
            totalProcessed: (_eggState.normalizedRows || []).length,
            newAfterDedup: (_eggState.newRows || []).length,
            excluded: _eggState.excludedKeys.size,
            finalCount: keep.length,
            totalCartons: keep.reduce((s, r) => s + Number(r.quantity||0), 0),
            // Surface silently-dropped row counts so the operator can explain
            // why totals look short (in-batch dups + future-dated rows).
            droppedDupes: _eggState.droppedDupes || 0,
            droppedFutureDated: _eggState.droppedFutureDated || 0
        };
        _eggState.currentPhase = 3;
        await eggRerenderTab(eggRenderRunTab);
    };

    const eggRenderPhase3 = (host) => {
        const s = _eggState.stats || {};
        host.innerHTML = `
            <div class="egg-phase-banner" style="display:flex;gap:8px;margin-bottom:20px;">
                <div style="flex:1;padding:10px;background:var(--gray-100);border-left:4px solid var(--gray-300);border-radius:6px;color:var(--gray-500);">
                    <strong>Phase 1:</strong> Upload
                </div>
                <div style="flex:1;padding:10px;background:var(--gray-100);border-left:4px solid var(--gray-300);border-radius:6px;color:var(--gray-500);">
                    <strong>Phase 2:</strong> Reconcile
                </div>
                <div style="flex:1;padding:10px;background:#fef3c7;border-left:4px solid #f59e0b;border-radius:6px;">
                    <strong>Phase 3:</strong> Preview &amp; Commit
                </div>
            </div>

            <div style="display:grid;grid-template-columns:repeat(5, 1fr);gap:12px;margin-bottom:20px;">
                <div style="background:white;padding:14px;border-radius:8px;border:1px solid var(--gray-200);text-align:center;">
                    <div style="color:var(--gray-500);font-size:11px;text-transform:uppercase;">Total Processed</div>
                    <div style="font-size:22px;font-weight:700;">${s.totalProcessed || 0}</div>
                </div>
                <div style="background:white;padding:14px;border-radius:8px;border:1px solid var(--gray-200);text-align:center;">
                    <div style="color:var(--gray-500);font-size:11px;text-transform:uppercase;">New After Dedup</div>
                    <div style="font-size:22px;font-weight:700;color:#059669;">${s.newAfterDedup || 0}</div>
                </div>
                <div style="background:white;padding:14px;border-radius:8px;border:1px solid var(--gray-200);text-align:center;">
                    <div style="color:var(--gray-500);font-size:11px;text-transform:uppercase;">Reconciled (excluded)</div>
                    <div style="font-size:22px;font-weight:700;color:#dc2626;">${s.excluded || 0}</div>
                </div>
                <div style="background:white;padding:14px;border-radius:8px;border:1px solid var(--gray-200);text-align:center;">
                    <div style="color:var(--gray-500);font-size:11px;text-transform:uppercase;">To Ship</div>
                    <div style="font-size:22px;font-weight:700;color:#f59e0b;">${s.finalCount || 0}</div>
                </div>
                <div style="background:white;padding:14px;border-radius:8px;border:1px solid var(--gray-200);text-align:center;">
                    <div style="color:var(--gray-500);font-size:11px;text-transform:uppercase;">Total Cartons</div>
                    <div style="font-size:22px;font-weight:700;">${s.totalCartons || 0}</div>
                </div>
            </div>
            ${(s.droppedDupes || s.droppedFutureDated) ? `
            <div style="background:#fffbeb;border:1px solid #f59e0b;border-radius:8px;padding:10px 14px;margin-bottom:16px;font-size:12px;color:#92400e;">
                <i class="fas fa-info-circle"></i> Rows dropped before this preview:
                ${s.droppedDupes ? `<strong>${s.droppedDupes}</strong> duplicate (same line in both files)` : ''}${(s.droppedDupes && s.droppedFutureDated) ? ' · ' : ''}${s.droppedFutureDated ? `<strong>${s.droppedFutureDated}</strong> future-dated (order date after today)` : ''}.
            </div>` : ''}

            <div style="background:white;padding:20px;border-radius:12px;border:1px solid var(--gray-200);margin-bottom:16px;">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
                    <h3 style="margin:0;">Farm Order <span style="font-size:12px;color:var(--gray-500);font-weight:normal;">(editable — fill in JB values manually before sending)</span></h3>
                    <div>
                        <button class="btn secondary btn-sm" onclick="app.eggResetFarmOrderText()"><i class="fas fa-undo"></i> Reset</button>
                        <button class="btn secondary btn-sm" onclick="app.eggCopyFarmOrder()"><i class="fas fa-copy"></i> Copy</button>
                        <button class="btn secondary btn-sm" onclick="app.eggDownloadFarmOrder()"><i class="fas fa-download"></i> Download .txt</button>
                    </div>
                </div>
                <textarea id="egg-farm-order-text" style="width:100%;background:#f8fafc;padding:16px;border:1px solid var(--gray-200);border-radius:6px;font-family:monospace;font-size:13px;line-height:1.6;min-height:340px;resize:vertical;box-sizing:border-box;">${_eggState.farmOrderText}</textarea>
                <div style="font-size:11px;color:var(--gray-500);margin-top:6px;">
                    <i class="fas fa-info-circle"></i> JB numbers default to 0 — edit this text directly to enter the actual JB KING/GOLD cartons before copying to the farm.
                </div>
            </div>

            <div style="background:white;padding:20px;border-radius:12px;border:1px solid var(--gray-200);margin-bottom:16px;">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
                    <h3 style="margin:0;">Channel Breakdown (KL / PG)</h3>
                    <div style="display:flex;gap:8px;">
                        <button class="btn secondary btn-sm" onclick="app.eggCopyChannelBreakdown()"><i class="fas fa-copy"></i> Copy</button>
                        <button class="btn secondary btn-sm" onclick="app.eggDownloadChannelBreakdownXlsx()"><i class="fas fa-file-excel"></i> Download Excel</button>
                    </div>
                </div>
                <div style="color:var(--gray-500);font-size:12px;margin-bottom:10px;">
                    Rows you pushed up to last week are excluded automatically — they are not in this download.
                </div>
                <div id="egg-channel-html">${_eggState.channelBreakdownHtml}</div>
            </div>

            <div style="margin-top:24px;display:flex;justify-content:space-between;">
                <button class="btn secondary" onclick="app.eggGoToPhase2()">
                    <i class="fas fa-arrow-left"></i> Back to Reconcile
                </button>
                <div>
                    <button class="btn secondary" onclick="app.eggDiscardRun()">
                        <i class="fas fa-times"></i> Discard Run
                    </button>
                    <button class="btn primary" onclick="app.eggCommitRun()" style="background:#059669;border-color:#059669;">
                        <i class="fas fa-check"></i> Commit &amp; Save
                    </button>
                </div>
            </div>
        `;
    };

    // Read the CURRENT value of the editable farm order textarea — user may
    // have typed in JB numbers or made other manual edits. Falls back to
    // _eggState.farmOrderText if the textarea isn't in the DOM (shouldn't happen
    // in normal Phase 3 flow but defensive).
    const eggGetFarmOrderText = () => {
        const ta = document.getElementById('egg-farm-order-text');
        return ta ? ta.value : (_eggState.farmOrderText || '');
    };

    const eggCopyFarmOrder = async () => {
        try {
            await navigator.clipboard.writeText(eggGetFarmOrderText());
            UI.toast.success('Copied to clipboard (including any JB edits)');
        } catch (err) {
            UI.toast.error('Copy failed');
        }
    };

    const eggCopyChannelBreakdown = async () => {
        try {
            await navigator.clipboard.writeText(_eggState.channelBreakdownText);
            UI.toast.success('Copied to clipboard');
        } catch (err) {
            UI.toast.error('Copy failed');
        }
    };

    // Shared builder — emits the SAME 2D array that the Excel download uses,
    // so the Google Sheets push and the .xlsx file are always byte-identical
    // in structure. Pass region='KL' or 'PG' to limit to that region's sections;
    // pass null/undefined to get all 4 sections (used by the Excel download).
    const eggBuildChannelBreakdownAoa = (keep, region = null) => {
        const sections = region
            ? _EGG_CHANNEL_SECTIONS.filter(s => s.region === region)
            : _EGG_CHANNEL_SECTIONS;
        // Columns: Section | Agent | Group | Order Date | Order No | Product Code | Product | Qty | Collect by Name | Date Collect | Remarks
        // Group shows the agent's group_name (e.g. "KL Cheras", "PG Center" for Wholesale;
        // "Kim", "June" etc. for Online). Section title/subtotal/blank rows leave Group empty.
        // The last 3 columns (Collect by Name / Date Collect / Remarks) are intentionally
        // left blank so the operations team can fill them in manually on the Google Sheet
        // after the orders are collected.
        const headerCols = ['Section', 'Agent', 'Group', 'Order Date', 'Order No', 'Product Code', 'Product', 'Qty', 'Collect by Name', 'Date Collect', 'Remarks'];
        const aoa = [headerCols];
        for (const sec of sections) {
            const sectionRows = keep.filter(r => r.region === sec.region && r.channel === sec.channel);
            const totalGold = sectionRows.filter(r => r.product === 'GOLD').reduce((s, r) => s + Number(r.quantity||0), 0);
            const totalKing = sectionRows.filter(r => r.product === 'KING').reduce((s, r) => s + Number(r.quantity||0), 0);
            aoa.push([sec.title, '', '', '', '', '', `GOLD ${totalGold}`, `KING ${totalKing}`, '', '', '']);
            if (sectionRows.length === 0) {
                aoa.push(['', 'No orders', '', '', '', '', '', '', '', '', '']);
            } else {
                for (const r of sectionRows) {
                    const dateStr = r.order_date_parsed ? eggFormatDateShort(r.order_date_parsed) : '-';
                    aoa.push(['', r.agent_name || '-', r.group_name || '', dateStr, r.order_no || '-', r.product_code || '-', r.product || '', Number(r.quantity)||0, '', '', '']);
                }
            }
            // Subtotal by ACTUAL product code (was hard-coded to FMLENX068/FMLEGG002,
            // which silently merged a 3rd code such as AGENTFMLENX060 into the GOLD line).
            const byCode = {};
            for (const r of sectionRows) {
                const code = r.product_code || '(no code)';
                if (!byCode[code]) byCode[code] = { qty: 0, product: r.product || '' };
                byCode[code].qty += Number(r.quantity) || 0;
            }
            for (const [code, info] of Object.entries(byCode)) {
                aoa.push(['', '', '', '', '', code, info.product, info.qty, '', '', '']);
            }
            aoa.push(['', '', '', '', '', '', '', '', '', '', '']); // blank separator row
        }
        return aoa;
    };

    // Generate an .xlsx of the Channel Breakdown — same sections as the on-screen
    // table (PG Wholesale → PG Online → KL Wholesale → KL Online), with a
    // section-header row + totals row between each group so it prints cleanly.
    // Pushed-up rows are already excluded from `keep`, matching the note in the UI.
    const eggDownloadChannelBreakdownXlsx = async () => {
        try {
            await window._ensureXlsx();
            const keep = (_eggState.newRows || []).filter(r => !_eggState.excludedKeys.has(r.unique_key));
            const aoa = eggBuildChannelBreakdownAoa(keep);
            const ws = XLSX.utils.aoa_to_sheet(aoa);
            ws['!cols'] = [{ wch: 18 }, { wch: 22 }, { wch: 18 }, { wch: 12 }, { wch: 16 }, { wch: 16 }, { wch: 10 }, { wch: 10 }, { wch: 20 }, { wch: 14 }, { wch: 24 }];
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, 'Channel Breakdown');
            const weekIso = eggFormatDateIso(_eggState.weekStartDate || eggGetCurrentMonday());
            XLSX.writeFile(wb, `channel_breakdown_${weekIso}.xlsx`);
            UI.toast.success('Excel file downloaded');
        } catch (err) {
            console.error('egg: xlsx download failed', err);
            UI.toast.error('Excel download failed: ' + (err.message || 'unknown'));
        }
    };

    // ==================== GOOGLE SHEETS PUSH ====================
    // Posts the same 2D array `eggBuildChannelBreakdownAoa` produces to an Apps
    // Script web app that appends it to the configured Google Sheet for the
    // region (KL or PG). The Apps Script handles concurrent edits with
    // LockService and finds the last filled row before writing — see
    // apps_script_egg_sheets.gs in the project root for the script the user
    // deploys.
    const eggPushOneRegionToSheets = async (url, region, aoa, attempt = 1) => {
        const payload = { region, rows: aoa };
        try {
            // Apps Script web apps redirect to googleusercontent for the response,
            // which breaks CORS on a JSON POST. We use text/plain to dodge the
            // preflight; Apps Script reads the raw body either way.
            const res = await fetch(url, {
                method: 'POST',
                headers: { 'Content-Type': 'text/plain;charset=utf-8' },
                body: JSON.stringify(payload),
                redirect: 'follow'
            });
            const text = await res.text();
            let json = null;
            try { json = JSON.parse(text); } catch (_) { /* not JSON */ }
            if (!res.ok || (json && json.ok === false)) {
                const msg = (json && json.error) || `HTTP ${res.status}`;
                // Retry once on lock-busy (Apps Script returns 503 when waitLock times out)
                if (attempt === 1 && (res.status === 503 || /lock/i.test(msg))) {
                    await new Promise(r => setTimeout(r, 2000));
                    return eggPushOneRegionToSheets(url, region, aoa, 2);
                }
                throw new Error(msg);
            }
            return { region, ok: true, ...(json || {}) };
        } catch (err) {
            console.warn(`egg: sheets push failed for ${region}`, err);
            return { region, ok: false, error: err.message || String(err) };
        }
    };

    const eggPushToGoogleSheets = async (keep) => {
        const url = _eggState.config?.google_sheets_webhook_url;
        if (!url) return { skipped: true, reason: 'no webhook URL configured' };
        const tasks = ['KL', 'PG'].map(region => {
            const aoa = eggBuildChannelBreakdownAoa(keep, region);
            // aoa[0] is always the header. The 4 section sections each emit at
            // least 2 rows (title + body or no-orders) + N code subtotals + blank.
            // If only the title rows are present with "No orders", we still
            // push so the gap + headers act as the section separator the user
            // wants. Skipping is only desired for entirely empty regions.
            const hasAnyOrderRows = aoa.slice(1).some(row => row[1] && row[1] !== 'No orders' && row[1] !== '');
            if (!hasAnyOrderRows) return { region, skipped: true };
            return eggPushOneRegionToSheets(url, region, aoa);
        });
        return Promise.all(tasks);
    };

    // Re-push from a saved run (Run History → "Re-push to Sheets" button).
    // Reconstructs the same `keep` shape from egg_processed_orders so the
    // builder returns the identical 2D array we would have pushed on commit.
    const eggRePushRunToSheets = async (runId) => {
        const url = _eggState.config?.google_sheets_webhook_url;
        if (!url) {
            UI.toast.error('Google Sheets webhook URL not configured (Config tab).');
            return;
        }
        if (!confirm('Re-push this run\'s Channel Breakdown to both Google Sheets? It will append below the current last row of each sheet.')) return;
        try {
            UI.toast.info('Pushing to Google Sheets...');
            const orders = await AppDataStore.query('egg_processed_orders', { run_id: runId }) || [];
            const keep = orders
                .filter(o => !o.excluded_reason)
                .map(o => ({
                    region: o.region,
                    channel: o.channel,
                    product: o.product,
                    product_code: o.product_code,
                    quantity: o.quantity,
                    agent_name: o.agent_name,
                    order_no: o.order_no,
                    order_date_parsed: o.order_date ? new Date(o.order_date) : null,
                    group_name: o.group_name
                }));
            const results = await eggPushToGoogleSheets(keep);
            if (results && results.skipped) {
                UI.toast.error('Webhook URL not configured.');
                return;
            }
            const failed = (results || []).filter(r => r && r.ok === false);
            const skipped = (results || []).filter(r => r && r.skipped);
            const ok = (results || []).filter(r => r && r.ok === true);
            if (failed.length === 0) {
                UI.toast.success(`Pushed: ${ok.map(r => r.region).join(', ') || 'nothing (regions empty)'}${skipped.length ? ` • Skipped (empty): ${skipped.map(r => r.region).join(', ')}` : ''}`);
            } else {
                const msg = failed.map(r => `${r.region}: ${r.error}`).join(' | ');
                UI.toast.error(`Re-push failed — ${msg}`);
            }
        } catch (err) {
            console.error('egg: re-push failed', err);
            UI.toast.error('Re-push failed: ' + (err.message || 'unknown'));
        }
    };

    const eggDownloadFarmOrder = () => {
        const text = eggGetFarmOrderText() + '\n' + _eggState.channelBreakdownText;
        const blob = new Blob([text], { type: 'text/plain;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `farm_order_${eggFormatDateIso(new Date())}.txt`;
        a.click();
        URL.revokeObjectURL(url);
    };

    // Re-generate the farm order text from the current run (resets any JB edits)
    const eggResetFarmOrderText = () => {
        const ta = document.getElementById('egg-farm-order-text');
        if (ta) ta.value = _eggState.farmOrderText;
        UI.toast.info('Farm order text reset to auto-generated value');
    };

    const eggDiscardRun = async () => {
        if (!confirm('Discard this run? No data will be saved.')) return;
        eggResetRun();
    };

    const eggCommitRun = async () => {
        if (!confirm('Commit this farm order? Processed rows will be saved to history.')) return;
        const keep = (_eggState.newRows || []).filter(r => !_eggState.excludedKeys.has(r.unique_key));
        const excluded = (_eggState.newRows || []).filter(r => _eggState.excludedKeys.has(r.unique_key));
        const weekIso = eggFormatDateIso(_eggState.weekStartDate || eggGetCurrentMonday());
        const now = new Date().toISOString();
        const runBy = _state.cu?.full_name || _state.cu?.email || 'unknown';

        try {
            UI.toast.info('Saving run...');
            // 1. Save run history first to get a run_id
            const summary = eggAggregate(keep);
            const topUp = _eggState.lastWeekTopUp || { GOLD: 0, KING: 0 };
            const runRec = await AppDataStore.create('egg_run_history', {
                run_at: now,
                week_start_date: weekIso,
                csv_filename: _eggState.csvFile?.name || null,
                excel_filename: _eggState.xlsxFile?.name || null,
                rows_processed: (_eggState.normalizedRows || []).length,
                rows_new: keep.length,
                rows_excluded: excluded.length,
                urgent_applied: 0,
                reconciliations_applied: excluded.length,
                totals: summary,
                // Use the edited textarea value — captures any JB numbers the
                // user typed in manually before clicking Commit.
                farm_order_text: eggGetFarmOrderText(),
                channel_breakdown_text: _eggState.channelBreakdownText,
                // Record the user's top-up input alongside the pushed-up keys
                // for audit — all lives in the same JSON column.
                reconciliation_log: {
                    last_week_top_up: { GOLD: Number(topUp.GOLD)||0, KING: Number(topUp.KING)||0 },
                    pushed_up_keys: Array.from(_eggState.excludedKeys || [])
                },
                run_by: runBy
            });
            const runId = runRec?.id;

            // 2. Save kept rows to processed_orders (per-row try/catch so one bad
            //    row doesn't abort the whole commit — we'd rather save 99/100 and
            //    report the failure than lose everything on a unique-key clash)
            let rowErrors = 0;
            const rowErrorDetails = [];
            // Row payload builder (keep + excluded share the base shape).
            const _eggRow = (r, extra) => Object.assign({
                unique_key: r.unique_key,
                order_no: r.order_no,
                product: r.product,
                product_code: r.product_code || null,
                quantity: r.quantity,
                region: r.region,
                agent_name: r.agent_name,
                channel: r.channel,
                source: r.source,
                group_name: r.group_name,
                order_date: r.order_date_parsed,
                week_start: weekIso,
                processed_at: now,
                run_id: runId
            }, extra || {});
            const _allPayloads = keep.map(r => _eggRow(r))
                .concat(excluded.map(r => _eggRow(r, { reconciled_with_urgent_id: null, excluded_reason: 'Pushed up to previous week top-up' })));

            // Fast path: ONE bulk upsert. egg_processed_orders has UNIQUE(unique_key),
            // so a clash (a row already saved by a prior run / within-batch dup) is
            // IGNORED, not an error — re-running a partial commit can't duplicate.
            // On a genuine (non-clash) error the whole statement fails, so fall back
            // to per-row upsert: good rows still commit (idempotent), only bad rows
            // count as errors — preserving the "save 99/100, report 1" behavior.
            try {
                if (_allPayloads.length) {
                    await AppDataStore.upsertMany('egg_processed_orders', _allPayloads, { onConflict: 'unique_key', ignoreDuplicates: true });
                }
            } catch (bulkErr) {
                console.warn('egg: bulk upsert failed, falling back to per-row', bulkErr);
                for (const p of _allPayloads) {
                    try {
                        await AppDataStore.upsertMany('egg_processed_orders', [p], { onConflict: 'unique_key', ignoreDuplicates: true });
                    } catch (rowErr) {
                        rowErrors++;
                        rowErrorDetails.push({ key: p.unique_key, err: rowErr.message });
                        console.warn('egg: row save failed', p.unique_key, rowErr);
                    }
                }
            }

            // Simplified flow: no urgent-order table sync needed — pushed-up rows
            // already land in egg_processed_orders with excluded_reason above.

            if (rowErrors > 0) {
                UI.toast.error(`Run committed with ${rowErrors} row error(s) — check browser console for details.`);
                console.error('egg: rowErrorDetails', rowErrorDetails);
            } else {
                UI.toast.success(`Run committed. ${keep.length} rows saved, ${excluded.length} pushed up.`);
            }

            // 4. Push the Channel Breakdown to Google Sheets (KL + PG).
            //    Failures here do NOT roll back the commit — the Supabase data
            //    is already safe. We surface failures via a sticky-style toast
            //    and the user can re-push from Run History at any time.
            try {
                const pushResults = await eggPushToGoogleSheets(keep);
                if (pushResults && pushResults.skipped) {
                    UI.toast.info('Google Sheets push skipped — webhook URL not set (Config tab).');
                } else if (Array.isArray(pushResults)) {
                    const failed = pushResults.filter(r => r && r.ok === false);
                    const ok = pushResults.filter(r => r && r.ok === true);
                    const skipped = pushResults.filter(r => r && r.skipped);
                    if (failed.length === 0) {
                        const okMsg = ok.length ? `Synced to Google Sheets: ${ok.map(r => r.region).join(', ')}` : 'Google Sheets sync — both regions empty';
                        const skipMsg = skipped.length ? ` • Skipped (no rows): ${skipped.map(r => r.region).join(', ')}` : '';
                        UI.toast.success(okMsg + skipMsg);
                    } else {
                        const detail = failed.map(r => `${r.region}: ${r.error}`).join(' | ');
                        UI.toast.error(`Google Sheets sync FAILED for ${failed.map(r => r.region).join(', ')} — re-push from Run History. (${detail})`);
                        console.error('egg: sheets push failures', failed);
                    }
                }
            } catch (sheetErr) {
                console.error('egg: sheets push threw', sheetErr);
                UI.toast.error(`Google Sheets sync threw: ${sheetErr.message || 'unknown'} — re-push from Run History.`);
            }

            eggResetRun();
        } catch (err) {
            console.error('egg: commit failed', err);
            UI.toast.error('Commit failed: ' + (err.message || 'unknown'));
        }
    };

    // ==================== TAB 2 — URGENT ORDERS ====================

    const eggRenderUrgentTab = async (host) => {
        const filter = _eggState.urgentFilter || 'active';
        let urgents = [];
        try {
            urgents = await AppDataStore.query('egg_urgent_orders', {}) || [];
        } catch (err) {
            UI.toast.error('Failed to load urgent orders');
        }
        urgents.sort((a,b) => String(b.week_start_date||'').localeCompare(String(a.week_start_date||'')));

        const filterFn = {
            active: u => ['pending','applied'].includes(u.status),
            resolved: u => ['reconciled','absorbed'].includes(u.status),
            stale: u => ['expired','cancelled'].includes(u.status),
            all: u => true
        };
        const filtered = urgents.filter(filterFn[filter] || filterFn.all);

        const activeCount = urgents.filter(filterFn.active).length;
        const appliedCount = urgents.filter(u => u.status === 'applied').length;

        const rowsHtml = filtered.length === 0 ?
            `<tr><td colspan="9" style="text-align:center;padding:20px;color:var(--gray-500);">No urgent orders.</td></tr>` :
            filtered.map(u => {
                const statusColor = {
                    pending:'#f59e0b', applied:'#3b82f6', reconciled:'#059669',
                    absorbed:'#6b7280', expired:'#6b7280', cancelled:'#6b7280'
                }[u.status] || '#6b7280';
                const actions = (u.status === 'pending') ? `
                    <button class="btn-icon" title="Edit" onclick="event.stopPropagation();app.eggEditUrgent(${u.id})"><i class="fas fa-edit"></i></button>
                    <button class="btn-icon" title="Cancel" onclick="event.stopPropagation();app.eggCancelUrgent(${u.id})"><i class="fas fa-times"></i></button>
                ` : (u.status === 'applied') ? `
                    <button class="btn-icon" title="Reconcile manually" onclick="event.stopPropagation();app.eggReconcileManually(${u.id})"><i class="fas fa-link"></i></button>
                    <button class="btn-icon" title="Mark expired" onclick="event.stopPropagation();app.eggExpireUrgent(${u.id})"><i class="fas fa-clock"></i></button>
                ` : '';
                return `
                    <tr style="border-top:1px solid var(--gray-200);">
                        <td style="padding:8px;">${escapeHtml(u.week_start_date || '-')}</td>
                        <td style="padding:8px;">${escapeHtml(u.agent_name || '-')}</td>
                        <td style="padding:8px;">${escapeHtml(u.product || '-')}</td>
                        <td style="padding:8px;">${escapeHtml(u.region || '-')}</td>
                        <td style="padding:8px;text-align:right;">${escapeHtml(String(u.quantity ?? ''))}</td>
                        <td style="padding:8px;">${escapeHtml(u.channel || 'Wholesale')}</td>
                        <td style="padding:8px;"><span style="background:${statusColor};color:white;padding:2px 8px;border-radius:10px;font-size:11px;">${escapeHtml(u.status || '')}</span></td>
                        <td style="padding:8px;font-size:12px;color:var(--gray-600);">${escapeHtml(u.notes || '')}</td>
                        <td style="padding:8px;">${actions}</td>
                    </tr>
                `;
            }).join('');

        host.innerHTML = `
            <div style="background:#eff6ff;border:1px solid #3b82f6;border-radius:8px;padding:14px;margin-bottom:16px;">
                <strong><i class="fas fa-eye"></i> Watch Board:</strong>
                ${appliedCount} urgent order${appliedCount === 1 ? '' : 's'} currently applied and watching for matching invoices.
                ${activeCount} total active (pending + applied).
            </div>

            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
                <div style="display:flex;gap:6px;">
                    <button class="btn ${filter==='active'?'primary':'secondary'} btn-sm" onclick="app.eggSetUrgentFilter('active')">Active</button>
                    <button class="btn ${filter==='resolved'?'primary':'secondary'} btn-sm" onclick="app.eggSetUrgentFilter('resolved')">Resolved</button>
                    <button class="btn ${filter==='stale'?'primary':'secondary'} btn-sm" onclick="app.eggSetUrgentFilter('stale')">Stale</button>
                    <button class="btn ${filter==='all'?'primary':'secondary'} btn-sm" onclick="app.eggSetUrgentFilter('all')">All</button>
                </div>
                <button class="btn primary" onclick="app.eggOpenAddUrgentModal()">
                    <i class="fas fa-plus"></i> Add Urgent Order
                </button>
            </div>

            <div style="background:white;padding:16px;border-radius:12px;border:1px solid var(--gray-200);">
                <table style="width:100%;border-collapse:collapse;">
                    <thead>
                        <tr style="background:var(--gray-50);text-align:left;">
                            <th scope="col" style="padding:8px;">Week</th>
                            <th scope="col" style="padding:8px;">Agent</th>
                            <th scope="col" style="padding:8px;">Product</th>
                            <th scope="col" style="padding:8px;">Region</th>
                            <th scope="col" style="padding:8px;text-align:right;">Qty</th>
                            <th scope="col" style="padding:8px;">Channel</th>
                            <th scope="col" style="padding:8px;">Status</th>
                            <th scope="col" style="padding:8px;">Notes</th>
                            <th scope="col" style="padding:8px;">Actions</th>
                        </tr>
                    </thead>
                    <tbody>${rowsHtml}</tbody>
                </table>
            </div>
        `;
    };

    const eggSetUrgentFilter = async (f) => {
        _eggState.urgentFilter = f;
        await eggRerenderTab(eggRenderUrgentTab);
    };

    const eggOpenAddUrgentModal = (editId) => {
        const isEdit = !!editId;
        const existing = isEdit ? (_eggState.urgentOrders || []).find(u => u.id === editId) : null;
        const weekIso = existing?.week_start_date || eggFormatDateIso(_eggState.weekStartDate || eggGetCurrentMonday());
        const content = `
            <div style="display:grid;gap:12px;min-width:400px;">
                <input type="hidden" id="egg-urg-id" value="${editId || ''}">
                <div>
                    <label style="font-weight:600;display:block;margin-bottom:4px;">Agent Name</label>
                    <input type="text" id="egg-urg-agent" class="form-control" value="${escapeHtml(existing?.agent_name || '')}">
                </div>
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                    <div>
                        <label style="font-weight:600;display:block;margin-bottom:4px;">Product</label>
                        <select id="egg-urg-product" class="form-control">
                            <option value="GOLD" ${existing?.product==='GOLD'?'selected':''}>GOLD</option>
                            <option value="KING" ${existing?.product==='KING'?'selected':''}>KING</option>
                        </select>
                    </div>
                    <div>
                        <label style="font-weight:600;display:block;margin-bottom:4px;">Region</label>
                        <select id="egg-urg-region" class="form-control">
                            <option value="KL" ${existing?.region==='KL'?'selected':''}>KL</option>
                            <option value="PG" ${existing?.region==='PG'?'selected':''}>PG</option>
                        </select>
                    </div>
                </div>
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
                    <div>
                        <label style="font-weight:600;display:block;margin-bottom:4px;">Quantity (cartons)</label>
                        <input type="number" id="egg-urg-qty" class="form-control" min="1" value="${existing?.quantity || 1}">
                    </div>
                    <div>
                        <label style="font-weight:600;display:block;margin-bottom:4px;">Channel</label>
                        <select id="egg-urg-channel" class="form-control">
                            <option value="Wholesale" ${existing?.channel==='Wholesale'?'selected':''}>Wholesale</option>
                            <option value="Online" ${existing?.channel==='Online'?'selected':''}>Online</option>
                        </select>
                    </div>
                </div>
                <div>
                    <label style="font-weight:600;display:block;margin-bottom:4px;">Week Start Date</label>
                    <input type="date" id="egg-urg-week" class="form-control" value="${weekIso}">
                </div>
                <div>
                    <label style="font-weight:600;display:block;margin-bottom:4px;">Notes (optional)</label>
                    <textarea id="egg-urg-notes" class="form-control" rows="2">${escapeHtml(existing?.notes || '')}</textarea>
                </div>
            </div>
        `;
        UI.showModal(isEdit ? 'Edit Urgent Order' : 'Add Urgent Order', content, [
            { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
            { label: isEdit ? 'Save' : 'Add', type: 'primary', action: 'app.eggSaveUrgentModal()' }
        ]);
    };

    const eggSaveUrgentModal = async () => {
        const id = document.getElementById('egg-urg-id')?.value;
        const agent = document.getElementById('egg-urg-agent')?.value?.trim();
        const product = document.getElementById('egg-urg-product')?.value;
        const region = document.getElementById('egg-urg-region')?.value;
        const qty = parseInt(document.getElementById('egg-urg-qty')?.value || '0', 10);
        const channel = document.getElementById('egg-urg-channel')?.value;
        const week = document.getElementById('egg-urg-week')?.value;
        const notes = document.getElementById('egg-urg-notes')?.value;
        if (!agent || !qty || qty <= 0) {
            UI.toast.error('Agent and positive quantity required');
            return;
        }
        try {
            if (id) {
                await AppDataStore.update('egg_urgent_orders', parseInt(id,10), {
                    agent_name: agent, product, region, quantity: qty, channel,
                    week_start_date: week, notes: notes || null
                });
                UI.toast.success('Urgent order updated');
            } else {
                await AppDataStore.create('egg_urgent_orders', {
                    agent_name: agent, product, region, quantity: qty, channel,
                    week_start_date: week, status: 'pending',
                    notes: notes || null,
                    created_by: _state.cu?.full_name || _state.cu?.email || 'unknown'
                });
                UI.toast.success('Urgent order added');
            }
            UI.hideModal();
            await eggRerenderTab(eggRenderUrgentTab);
        } catch (err) {
            UI.toast.error('Save failed: ' + (err.message || 'unknown'));
        }
    };

    const eggEditUrgent = (id) => {
        // Load fresh from DB for edit
        AppDataStore.query('egg_urgent_orders', { id }).then(rows => {
            if (rows && rows.length > 0) {
                _eggState.urgentOrders = [rows[0]];
                eggOpenAddUrgentModal(id);
            }
        }).catch(err => { UI.toast.error("Failed to load urgent order: " + (err?.message||err)); });
    };

    const eggCancelUrgent = async (id) => {
        if (!confirm('Cancel this urgent order?')) return;
        try {
            await AppDataStore.update('egg_urgent_orders', id, { status: 'cancelled' });
            UI.toast.success('Urgent order cancelled');
            await eggRerenderTab(eggRenderUrgentTab);
        } catch (err) {
            UI.toast.error('Cancel failed: ' + (err.message || 'unknown'));
        }
    };

    const eggExpireUrgent = async (id) => {
        if (!confirm('Mark this urgent order as expired? Use this when you confirm the agent never created the real sales order.')) return;
        try {
            await AppDataStore.update('egg_urgent_orders', id, { status: 'expired' });
            UI.toast.success('Marked expired');
            await eggRerenderTab(eggRenderUrgentTab);
        } catch (err) {
            UI.toast.error('Update failed: ' + (err.message || 'unknown'));
        }
    };

    const eggReconcileManually = async (id) => {
        // Show a picker of recent processed orders to link against
        try {
            const urgent = (await AppDataStore.query('egg_urgent_orders', { id }))?.[0];
            if (!urgent) { UI.toast.error('Urgent order not found'); return; }
            // Paginate past the 1000-row cap so the candidate picker isn't
            // silently limited to a heap-ordered first 1000 as history grows.
            const candidates = await AppDataStore.queryPaged('egg_processed_orders', {
                filters: { product: urgent.product, region: urgent.region },
                max: 200000
            }) || [];
            const unlinkedCandidates = candidates.filter(c => !c.reconciled_with_urgent_id && !c.excluded_reason);
            if (unlinkedCandidates.length === 0) {
                UI.toast.info('No matching processed orders found to link against');
                return;
            }
            const sorted = unlinkedCandidates.sort((a,b) => String(b.processed_at||'').localeCompare(String(a.processed_at||'')));
            const recentSlice = sorted.slice(0, 50);
            const content = `
                <div style="max-height:60vh;overflow-y:auto;">
                    <div style="padding:10px;background:#fef3c7;border-left:4px solid #f59e0b;border-radius:6px;margin-bottom:12px;">
                        Link urgent #${id} (${escapeHtml(urgent.agent_name || '-')} • ${escapeHtml(urgent.product || '-')} • ${escapeHtml(urgent.region || '-')} • ${escapeHtml(String(urgent.quantity ?? ''))} cartons) to one of these processed orders:
                    </div>
                    <table style="width:100%;border-collapse:collapse;">
                        <thead>
                            <tr style="background:var(--gray-50);text-align:left;">
                                <th scope="col" style="padding:6px;">Select</th>
                                <th scope="col" style="padding:6px;">Order No</th>
                                <th scope="col" style="padding:6px;">Agent</th>
                                <th scope="col" style="padding:6px;">Qty</th>
                                <th scope="col" style="padding:6px;">Week</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${recentSlice.map(c => `
                                <tr style="border-top:1px solid var(--gray-200);">
                                    <td style="padding:6px;"><input type="radio" name="egg-reconcile-pick" value="${c.id}" data-key="${escapeHtml(String(c.unique_key ?? ''))}"></td>
                                    <td style="padding:6px;font-family:monospace;font-size:12px;">${escapeHtml(c.order_no || '-')}</td>
                                    <td style="padding:6px;">${escapeHtml(c.agent_name || '-')}</td>
                                    <td style="padding:6px;">${c.quantity}</td>
                                    <td style="padding:6px;">${escapeHtml(c.week_start || '-')}</td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>
                </div>
            `;
            UI.showModal('Manual Reconciliation', content, [
                { label: 'Cancel', type: 'secondary', action: 'UI.hideModal()' },
                { label: 'Link & Reconcile', type: 'primary', action: `app.eggCompleteManualReconcile(${id})` }
            ]);
        } catch (err) {
            UI.toast.error('Reconcile failed: ' + (err.message || 'unknown'));
        }
    };

    const eggCompleteManualReconcile = async (urgentId) => {
        const picked = document.querySelector('input[name="egg-reconcile-pick"]:checked');
        if (!picked) { UI.toast.error('Select a processed order to link'); return; }
        const processedId = parseInt(picked.value, 10);
        const uniqueKey = picked.getAttribute('data-key');
        const now = new Date().toISOString();
        const runBy = _state.cu?.full_name || _state.cu?.email || 'unknown';
        try {
            await AppDataStore.update('egg_urgent_orders', urgentId, {
                status: 'reconciled',
                reconciled_at: now,
                reconciled_with_unique_key: uniqueKey,
                reconciled_by: runBy
            });
            await AppDataStore.update('egg_processed_orders', processedId, {
                reconciled_with_urgent_id: urgentId,
                excluded_reason: `Manually reconciled with urgent #${urgentId}`
            });
            UI.hideModal();
            UI.toast.success('Manual reconciliation saved');
            await eggRerenderTab(eggRenderUrgentTab);
        } catch (err) {
            UI.toast.error('Reconcile failed: ' + (err.message || 'unknown'));
        }
    };

    // ==================== TAB 3 — RUN HISTORY ====================

    const eggRenderHistoryTab = async (host) => {
        let runs = [];
        try {
            runs = await AppDataStore.query('egg_run_history', {}) || [];
        } catch (err) {
            UI.toast.error('Failed to load history');
        }
        runs.sort((a,b) => String(b.run_at||'').localeCompare(String(a.run_at||'')));

        const rowsHtml = runs.length === 0 ?
            `<tr><td colspan="8" style="text-align:center;padding:20px;color:var(--gray-500);">No runs yet.</td></tr>` :
            runs.map(r => {
                const totals = r.totals || {};
                const tot = (totals.KL?.GOLD || 0) + (totals.KL?.KING || 0) + (totals.PG?.GOLD || 0) + (totals.PG?.KING || 0);
                return `
                    <tr style="border-top:1px solid var(--gray-200);">
                        <td style="padding:8px;font-size:12px;">${r.run_at ? new Date(r.run_at).toLocaleString() : '-'}</td>
                        <td style="padding:8px;">${escapeHtml(r.week_start_date || '-')}</td>
                        <td style="padding:8px;font-size:12px;">${escapeHtml(r.csv_filename || '-')} / ${escapeHtml(r.excel_filename || '-')}</td>
                        <td style="padding:8px;text-align:right;">${r.rows_new || 0}</td>
                        <td style="padding:8px;text-align:right;">${r.rows_excluded || 0}</td>
                        <td style="padding:8px;text-align:right;">${tot}</td>
                        <td style="padding:8px;">${escapeHtml(r.run_by || '-')}</td>
                        <td style="padding:8px;">
                            <button class="btn-icon" title="View" onclick="app.eggViewRun(${r.id})"><i class="fas fa-eye"></i></button>
                            <button class="btn-icon" title="Re-push to Google Sheets" onclick="app.eggRePushRunToSheets(${r.id})"><i class="fas fa-share-square" style="color:#0ea5e9;"></i></button>
                        </td>
                    </tr>
                `;
            }).join('');

        host.innerHTML = `
            <div style="background:white;padding:16px;border-radius:12px;border:1px solid var(--gray-200);">
                <h3 style="margin-top:0;">Run History</h3>
                <table style="width:100%;border-collapse:collapse;">
                    <thead>
                        <tr style="background:var(--gray-50);text-align:left;">
                            <th scope="col" style="padding:8px;">Run At</th>
                            <th scope="col" style="padding:8px;">Week</th>
                            <th scope="col" style="padding:8px;">Files</th>
                            <th scope="col" style="padding:8px;text-align:right;">Rows</th>
                            <th scope="col" style="padding:8px;text-align:right;">Excluded</th>
                            <th scope="col" style="padding:8px;text-align:right;">Cartons</th>
                            <th scope="col" style="padding:8px;">Run By</th>
                            <th scope="col" style="padding:8px;">Actions</th>
                        </tr>
                    </thead>
                    <tbody>${rowsHtml}</tbody>
                </table>
            </div>
        `;
    };

    const eggViewRun = async (runId) => {
        try {
            const rows = await AppDataStore.query('egg_run_history', { id: runId });
            if (!rows || rows.length === 0) { UI.toast.error('Run not found'); return; }
            const r = rows[0];
            const content = `
                <div style="max-height:70vh;overflow-y:auto;min-width:600px;">
                    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:16px;">
                        <div style="padding:10px;background:var(--gray-50);border-radius:6px;">
                            <div style="font-size:11px;color:var(--gray-500);text-transform:uppercase;">Week</div>
                            <div style="font-weight:700;">${r.week_start_date || '-'}</div>
                        </div>
                        <div style="padding:10px;background:var(--gray-50);border-radius:6px;">
                            <div style="font-size:11px;color:var(--gray-500);text-transform:uppercase;">Rows Saved</div>
                            <div style="font-weight:700;color:#059669;">${r.rows_new || 0}</div>
                        </div>
                        <div style="padding:10px;background:var(--gray-50);border-radius:6px;">
                            <div style="font-size:11px;color:var(--gray-500);text-transform:uppercase;">Reconciled</div>
                            <div style="font-weight:700;color:#dc2626;">${r.rows_excluded || 0}</div>
                        </div>
                    </div>
                    <h4>Farm Order</h4>
                    <pre style="background:#f8fafc;padding:16px;border-radius:6px;font-family:monospace;font-size:13px;white-space:pre-wrap;">${escapeHtml(r.farm_order_text || '')}</pre>
                    <h4>Channel Breakdown</h4>
                    <pre style="background:#f8fafc;padding:16px;border-radius:6px;font-family:monospace;font-size:13px;white-space:pre-wrap;">${escapeHtml(r.channel_breakdown_text || '')}</pre>
                    ${(() => {
                        const byGroup = r.totals?.by_group;
                        if (!byGroup || !Object.keys(byGroup).length) return '';
                        const groupOrder = ['KL Cheras','SG Puchong & Sunway','KL Kepong','PG Center','PG Mainland','PG South'];
                        const seen = new Set();
                        let rows = '';
                        for (const g of groupOrder) {
                            if (byGroup[g] !== undefined) { rows += `<div style="display:flex;justify-content:space-between;padding:7px 12px;border-bottom:1px solid var(--gray-100);"><span>${escapeHtml(g)}</span><strong>${byGroup[g]} cartons</strong></div>`; seen.add(g); }
                        }
                        for (const [g, qty] of Object.entries(byGroup)) {
                            if (!seen.has(g)) rows += `<div style="display:flex;justify-content:space-between;padding:7px 12px;border-bottom:1px solid var(--gray-100);"><span>${escapeHtml(g)}</span><strong>${qty} cartons</strong></div>`;
                        }
                        return `<h4>Wholesales Group Summary</h4><div style="border:1px solid #d1fae5;border-radius:8px;overflow:hidden;margin-bottom:16px;"><div style="background:#ecfdf5;padding:8px 12px;font-weight:600;font-size:13px;color:#065f46;"><i class="fas fa-layer-group"></i> Wholesales Group Summary</div>${rows}</div>`;
                    })()}
                </div>
            `;
            UI.showModal(`Run ${r.id} — ${r.run_at ? new Date(r.run_at).toLocaleString() : ''}`, content, [
                { label: 'Close', type: 'secondary', action: 'UI.hideModal()' }
            ]);
        } catch (err) {
            UI.toast.error('View failed: ' + (err.message || 'unknown'));
        }
    };

    // ==================== TAB 4 — CONFIGURATION ====================

    const eggRenderConfigTab = async (host) => {
        await eggLoadConfig();
        const cfg = _eggState.config;
        const json = JSON.stringify(cfg, null, 2);
        host.innerHTML = `
            <div style="background:white;padding:20px;border-radius:12px;border:1px solid var(--gray-200);margin-bottom:16px;">
                <h3 style="margin-top:0;">Configuration</h3>
                <p style="color:var(--gray-500);font-size:13px;">
                    Edit the JSON configuration for region rules, product mapping, and wholesale groups.
                </p>
                <textarea id="egg-config-json" class="form-control" style="width:100%;height:380px;font-family:monospace;font-size:13px;">${escapeHtml(json)}</textarea>
                <div style="margin-top:14px;display:flex;gap:8px;">
                    <button class="btn primary" onclick="app.eggSaveConfigFromTextarea()"><i class="fas fa-save"></i> Save</button>
                    <button class="btn secondary" onclick="app.eggResetConfigToDefault()"><i class="fas fa-undo"></i> Reset to Defaults</button>
                </div>
            </div>
            <div style="background:white;padding:20px;border-radius:12px;border:1px solid var(--gray-200);">
                <h3 style="margin-top:0;">Wholesales Group Data</h3>
                <p style="color:var(--gray-500);font-size:13px;">
                    Patch historical runs that are missing the wholesales group breakdown (by_group).
                    Safe to run multiple times — only updates runs that are missing the data.
                </p>
                <button class="btn secondary" onclick="app.eggResyncGroupData()">
                    <i class="fas fa-sync-alt"></i> Re-sync Group Data on All Runs
                </button>
                <div id="egg-resync-status" style="margin-top:10px;font-size:13px;"></div>
            </div>
        `;
    };

    const eggSaveConfigFromTextarea = async () => {
        const text = document.getElementById('egg-config-json')?.value;
        try {
            const parsed = JSON.parse(text);
            await eggSaveConfig(parsed);
            await eggRerenderTab(eggRenderConfigTab);
        } catch (err) {
            UI.toast.error('Invalid JSON: ' + err.message);
        }
    };

    const eggResetConfigToDefault = async () => {
        if (!confirm('Reset configuration to defaults? Current values will be overwritten.')) return;
        await eggSaveConfig(eggDefaultConfig());
        await eggRerenderTab(eggRenderConfigTab);
    };

    const eggResyncGroupData = async () => {
        const statusEl = document.getElementById('egg-resync-status');
        if (statusEl) statusEl.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Loading runs…';
        try {
            const runs = await AppDataStore.query('egg_run_history', {}) || [];
            const toSync = runs.filter(r => !r.totals?.by_group);
            if (toSync.length === 0) {
                if (statusEl) statusEl.innerHTML = '<span style="color:#10b981;">✓ All runs already have group data.</span>';
                return;
            }
            if (statusEl) statusEl.innerHTML = `<i class="fas fa-spinner fa-spin"></i> Syncing ${toSync.length} run(s)…`;
            let done = 0;
            for (const run of toSync) {
                const orders = await AppDataStore.query('egg_processed_orders', { run_id: run.id }) || [];
                const kept = orders.filter(o => !o.excluded_reason);
                const byGroup = {};
                for (const r of kept) {
                    if (r.channel !== 'Wholesale') continue;
                    const g = r.group_name;
                    if (g) byGroup[g] = (byGroup[g] || 0) + (Number(r.quantity) || 0);
                }
                const updatedTotals = { ...(run.totals || {}), by_group: byGroup };
                await AppDataStore.update('egg_run_history', run.id, { totals: updatedTotals });
                done++;
                if (statusEl) statusEl.innerHTML = `<i class="fas fa-spinner fa-spin"></i> Syncing… ${done}/${toSync.length}`;
            }
            if (statusEl) statusEl.innerHTML = `<span style="color:#10b981;">✓ Synced ${done} run(s) successfully.</span>`;
            UI.toast.success(`Group data synced for ${done} run(s)`);
        } catch (err) {
            if (statusEl) statusEl.innerHTML = `<span style="color:#ef4444;">Error: ${err.message}</span>`;
            UI.toast.error('Re-sync failed: ' + err.message);
        }
    };

    // ==================== /EGG PURCHASING ====================
    // ── Register public surface on window.app ────────────────────────────
    // 1:1 with the names that were in script.js's return statement before
    // extraction. Called at chunk-load time so onclick="app.X(id)" works
    // immediately after the chunk's <script> tag fires.
    app.register('egg', {
        showEggPurchasingView,
        eggSwitchTab,
        eggRefresh,
        eggRerenderJsx,
        eggHandleCsvDrop,
        eggHandleCsvInput,
        eggHandleXlsxDrop,
        eggHandleXlsxInput,
        eggSetWeekStart,
        eggResetRun,
        eggGoToPhase1,
        eggGoToPhase2,
        eggGoToPhase3,
        eggToggleExclude,
        eggClearExclusions,
        eggSetLastWeekTopUp,
        eggCopyFarmOrder,
        eggCopyChannelBreakdown,
        eggDownloadChannelBreakdownXlsx,
        eggDownloadFarmOrder,
        eggResetFarmOrderText,
        eggDiscardRun,
        eggCommitRun,
        eggSetUrgentFilter,
        eggOpenAddUrgentModal,
        eggSaveUrgentModal,
        eggEditUrgent,
        eggCancelUrgent,
        eggExpireUrgent,
        eggReconcileManually,
        eggCompleteManualReconcile,
        eggViewRun,
        eggRePushRunToSheets,
        eggSaveConfigFromTextarea,
        eggResetConfigToDefault,
        eggResyncGroupData,
    });
})();
